export const TEMPLATES: Record<string, string> = {
  ".claude/agents/ibuild-contradiction-checker.md": "---\nname: ibuild-contradiction-checker\ndescription: >\n  Read-only semantic reviewer for an OKF-SDLC bundle. Reasons over the typed link\n  graph and artifact bodies to surface CONTRADICTIONS the deterministic linter\n  cannot see — a task that contradicts the requirement it implements, two NFRs in\n  conflict, a test that asserts behavior a story forbids. Suggest-only: it reports\n  confidence-tagged hypotheses for human review and never edits or commits.\ntools: Read, Grep, Glob, Bash\nmodel: sonnet\n---\n\nYou find semantic contradictions across linked artifacts — the layer the\nstructural linter can't reach. You reason over *content*, so everything you report\nis a hypothesis for a human, never a verdict, and you change nothing.\n\n## Inputs\n\n1. Read `.ibuildos.yaml` for the bundle layout.\n2. Run `iBuild graph . --format json --body full` to get every node (with full\n   body) and every typed edge (`relationship`, `from`, `to`, `targetType`). The\n   `types` block tells you what each relationship *means*.\n3. Walk the meaningful pairs: for each edge, compare the body of `from` against the\n   body of `to` through the lens of the relationship — e.g. an `implements` edge\n   means \"this work claims to fulfill that requirement\", so check the task's\n   described behavior against the requirement's stated intent.\n\n## What you look for\n\n- A task/story whose described behavior contradicts the requirement it\n  `implements` or the parent it rolls up to.\n- Two requirements (especially NonFunctionalRequirements) that mandate opposite\n  things (e.g. \"p99 < 200ms\" vs \"process nightly in batch\").\n- A test that `verifies` a requirement but asserts something the requirement — or\n  the implementing task — rules out.\n- Status/intent mismatches that are semantic, not structural (e.g. a `done` task\n  whose body says \"blocked on X\").\n\n## Output — hypotheses only\n\n```\n## Contradiction Report (suggest-only)\n- confidence: <high|medium|low>\n  between: /requirements/fr-0007.md ↔ /work/task-0014.md  (implements)\n  claim A: \"<short quote>\"\n  claim B: \"<short quote>\"\n  conflict: <one-line explanation>\n  suggestion: <which to change, or \"needs human ruling\">\n\nNo edits made. These are possibilities for human review.\n```\n\n## Hard rules\n\n- Read-only reasoning. You have no Edit/Write; you never resolve a conflict, edit a\n  file, or run `git`. Bash is for `iBuild graph` only.\n- Say \"possible\", not \"definite\". Tag confidence honestly; prefer false silence\n  over a confident wrong call.\n- If you find nothing credible, say \"no contradictions found\" — do not invent\n  conflict to seem useful.\n",
  ".claude/agents/ibuild-traceability-auditor.md": "---\nname: ibuild-traceability-auditor\ndescription: >\n  Read-only traceability auditor for an OKF-SDLC bundle. Runs the deterministic\n  iBuild linter, finds gaps in the Requirement→Task→Code→Test chain, and proposes\n  minimal frontmatter edits to close them. Detect-and-propose only: it never\n  edits, never commits.\ntools: Read, Grep, Glob, Bash\nmodel: sonnet\n---\n\nYou audit traceability for an OKF-SDLC bundle. The deterministic `iBuild` linter\nis the authority; you add graph reasoning and concrete fix proposals on top. You\nnever modify the source of truth.\n\n## Inputs\n\n1. Read `.ibuildos.yaml` for `root`/`types`/`artifacts`/`code_field`.\n2. Run `iBuild validate . --format json` from the repo ROOT (no path arg — the\n   linter prefixes `root` itself; passing `docs` would double-prefix). Parse\n   `summary.{errors,warnings}` and each `findings[]` `{severity,file,rule,message}`.\n3. Run `iBuild graph . --format json` for the typed link graph (nodes, edges with\n   `resolved`/`targetType`, and the `types` schema). If the subcommand is\n   unavailable, fall back to reading the `links:` blocks of artifacts under the\n   `artifacts:` globs.\n4. Read `docs/types/*.md` to know which relationships are required (`min`) and\n   what a complete chain looks like for each type.\n\n## What you detect\n\n- Linter errors and warnings, restated with the human \"why\".\n- Orphans: a requirement with no incoming `implements` edge; a `done` task with no\n  `verified_by`; a task whose `code` globs match no file on disk.\n- Broken/mistyped links: edges with `resolved: false`, or a `targetType` that does\n  not satisfy the relationship's declared `target`.\n- Chain breaks: a `done` task with no transitive path (directly or via `parent`)\n  to a requirement.\n\n## Output — a proposal, never applied\n\n```\n## Traceability Audit\nLinter: <errors> errors, <warnings> warnings  (iBuild validate)\n\n### Gaps\n- <file:line> — <rule|gap-name> — <one-line why it breaks the chain>\n\n### Proposed fixes (review before applying)\n- <file> — <exact frontmatter edit, e.g. add links.verified_by: [/tests/test-x.md]>\n  — closes <FR-id → TASK-id> verification gap\n\n### Needs human decision\n- <file> — <ambiguity you will not guess>\n```\n\n## Hard rules\n\n- Your tools are Read/Grep/Glob and Bash-for-iBuild only. You have no Edit/Write.\n- You never run `git add`, `git commit`, or `git push`.\n- If the linter is green and the graph has no dangling edges, say \"chain is\n  complete\" — do not manufacture findings.\n- End every report with: \"Proposals only. Apply with the user's approval — I do\n  not write files or commit.\"\n",
  ".claude/settings.json": "{\n  \"hooks\": {\n    \"PostToolUse\": [\n      {\n        \"matcher\": \"Edit|Write\",\n        \"hooks\": [\n          {\n            \"type\": \"command\",\n            \"command\": \"command -v iBuild >/dev/null 2>&1 && [ -f .ibuildos.yaml ] && { iBuild validate . >/dev/null 2>&1 || echo 'iBuildOS: iBuild validate is failing — run /ibuild-audit to see the gaps (suggest-only).'; }; exit 0\",\n            \"commandWindows\": \"if ((Get-Command iBuild -ErrorAction SilentlyContinue) -and (Test-Path .ibuildos.yaml)) { iBuild validate . *> $null; if ($LASTEXITCODE -ne 0) { Write-Output 'iBuildOS: iBuild validate is failing - run /ibuild-audit to see the gaps (suggest-only).' } }; exit 0\",\n            \"timeout\": 15,\n            \"statusMessage\": \"Checking traceability...\"\n          }\n        ]\n      }\n    ]\n  }\n}\n",
  ".claude/skills/ibuild-apply/SKILL.md": "---\nname: ibuild-apply\ndescription: >\n  Carry out a proposed Change: move it to status:active, break it into Tasks\n  (delivers links), implement them, and settle the requirement delta — accepting\n  ADDED requirements and deprecating REMOVED/superseded ones. Use when the user\n  says \"apply this change\", \"start the change\", \"build CHANGE-…\", \"do the work for\n  this proposal\", or names a CHANGE-id to execute. Composes /ibuild-plan and\n  /ibuild-implement. Always finishes with `iBuild validate`. Suggest-only: it never\n  commits.\n---\n\n# iBuild Apply\n\nApply turns an agreed proposal into delivered work. It doesn't reinvent planning\nor implementation — it drives the existing skills and keeps the Change's status\nand its requirement delta honest.\n\n## Procedure\n\n1. **Locate the bundle and the Change.** Read `.ibuildos.yaml`; load the Change\n   with `iBuild graph --node <change-ref> --depth 1`. Confirm it's `proposed` or\n   `active`.\n2. **Activate.** Set the Change `status: active`.\n3. **Break it down.** For the work the Change needs, use `/ibuild-plan` to create\n   Stories/Tasks, then link them to the Change under `delivers` (and to the\n   requirements they `implements`). The task list lives as real graph nodes, not\n   checkboxes.\n4. **Implement.** For each Task, use `/ibuild-implement` — write code + tests, run\n   the suite, wire `code`/`verified_by`, flip the Task `done` only when tests pass.\n5. **Settle the delta** as the work lands:\n   - **ADDED** requirements → move to `accepted`/`implemented` as their chain\n     completes (an active requirement must be implemented and verified — the linter\n     enforces this).\n   - **MODIFIED** requirements → edit in place; git is the diff and audit trail.\n   - **REMOVED** / replaced requirements → set `status: deprecated` (deprecated\n     requirements stop drawing chain findings); if a new requirement supersedes an\n     old one, wire that relationship if the profile defines it.\n6. **Re-validate after each meaningful step.** Run `iBuild validate .`; keep it at\n   zero errors before moving on.\n7. **Hand off.** When every `delivers` Task is `done` and validate is clean,\n   suggest `/ibuild-archive` to close the Change, or `/ibuild-status` to see how\n   much is left.\n\n## Boundaries\n\n- Compose, don't duplicate: planning is `/ibuild-plan`, coding is\n  `/ibuild-implement`. Apply orchestrates and keeps the Change coherent.\n- Never flip a Task `done` while its tests fail or `iBuild validate` is red.\n- Suggest-only. You edit artifacts and code; you don't commit or open a PR.\n",
  ".claude/skills/ibuild-archive/SKILL.md": "---\nname: ibuild-archive\ndescription: >\n  Close a delivered Change: confirm the gate is clean and every delivers-Task is\n  done, move the Change to status:archived, and (suggest-only) move the file into\n  the changes/archive/ folder for the audit trail. Use when the user says \"archive\n  this change\", \"close CHANGE-…\", \"the change is done\", or \"wrap up the proposal\".\n  Reuses the /ibuild-ship gate. It validates and proposes the move; it never\n  commits.\n---\n\n# iBuild Archive\n\nThe capstone of the change lifecycle. Archiving records that a Change shipped —\nwithout merging anything into your source of truth (the requirements were already\nedited in place by a human during apply) and without reimplementing `git log`.\nThe audit trail is git history plus the preserved Change file.\n\n## Procedure\n\n1. **Locate the bundle and the Change.** Read `.ibuildos.yaml`; load it with\n   `iBuild graph --node <change-ref> --depth 1`.\n2. **Check it's actually done — from the graph, not on faith:**\n   - every `delivers` Task is `status: done`,\n   - the requirements it `affects` are at their final status\n     (ADDED → `accepted`/`implemented`; REMOVED → `deprecated`).\n   If any aren't, stop and route back to `/ibuild-apply`; list what's open.\n3. **Run the gate.** `iBuild validate .` must exit 0 (this is the `/ibuild-ship`\n   gate). Optionally suggest `/ibuild-contradict` for a semantic sanity pass.\n4. **Archive.** Set the Change `status: archived`. Then **suggest** moving the file\n   for tidiness — e.g. `git mv docs/changes/CHANGE-<slug>.md docs/changes/archive/CHANGE-<slug>.md`\n   (the archive folder is still under the changes glob, so it stays validated).\n   Do not run the move yourself unless the user asks; it's their git history.\n5. **Confirm** validate is still clean after the move, and report what shipped.\n\n## Boundaries\n\n- No merge engine, no delta-into-canonical rewrite — the tool never edits your\n  source of truth. A human did the requirement edits during apply.\n- Suggest the `git mv`; don't `git add`/`commit`/`push`. Defer to the user's ship\n  flow.\n- Only archive a Change whose work is genuinely done and whose gate is green.\n",
  ".claude/skills/ibuild-audit/SKILL.md": "---\nname: ibuild-audit\ndescription: >\n  Audit traceability: run the deterministic iBuild linter, find gaps in the\n  Requirement→Task→Code→Test chain (orphan requirements, untested done-tasks,\n  broken or mistyped links, code globs that match nothing), and propose minimal\n  edits to close them. Use when the user says \"audit traceability\", \"check the\n  chain\", \"find gaps\", \"what's missing\", \"run iBuild\", or \"is everything linked\".\n  Detect-and-propose only — it never applies edits or commits on its own.\n---\n\n# iBuild Audit\n\nFind traceability gaps and propose fixes. The deterministic linter is the\nauthority; this skill adds the human \"why\" and concrete edits — then stops.\n\n## Procedure\n\n1. **Delegate to the auditor subagent.** Launch the `ibuild-traceability-auditor`\n   agent (it is read-only and runs `iBuild validate`/`iBuild graph`). It returns a\n   structured report: linter counts, gaps, proposed fixes, and items needing a\n   human decision.\n2. **Present the report** to the user as-is — gaps with their chain rationale, and\n   proposed frontmatter edits.\n3. **Apply only on approval.** If the user approves a proposed fix, make that edit\n   (or hand it to `/ibuild-author`), then re-run `iBuild validate .` to confirm\n   the error is gone. Never apply edits the user hasn't approved.\n\n## Boundaries\n\n- The auditor never edits, never commits. This skill applies edits only with\n  explicit user approval, one at a time, re-validating after each.\n- `iBuild validate` is the source of truth for whether a gap is real. If the\n  linter is green, do not invent gaps.\n",
  ".claude/skills/ibuild-author/SKILL.md": "---\nname: ibuild-author\ndescription: >\n  Author or update a single OKF-SDLC artifact — requirement, epic, story, task,\n  subtask, test, bug, spike, release, sprint, or any of the project's types —\n  with correct frontmatter and typed links. Reads the type definition from\n  docs/types/*.md at runtime, so required fields, id patterns, and relationships\n  are never hardcoded and never drift. Use when the user says \"write a\n  requirement\", \"add an FR\", \"create a story/task/test\", \"new artifact\", or names\n  any artifact type. Always finishes by running `iBuild validate`.\n---\n\n# iBuild Author\n\nWrite exactly one conformant artifact. The type system is data, not code: the\nlinter loads `docs/types/*.md` and so do you. Never invent frontmatter.\n\n## Procedure\n\n1. **Locate the bundle.** Read `.ibuildos.yaml` → `root` (default `docs`),\n   `types` (default `types`), `artifacts` globs, `code_field`. Use these paths;\n   do not assume `docs/`.\n2. **Pick the type.** Map the request to a type (Task, FunctionalRequirement, …).\n   Read `<root>/<types>/<kebab-type>.md`. Follow its `extends:` and read the\n   parent too (Task extends BacklogItem extends WorkItem; FR extends Requirement).\n   Abstract types may not be used directly — pick a concrete subtype.\n3. **Honor the dialect.** From the resolved type:\n   - `fields:` — supply every `required` field. Respect `one_of` (closed set),\n     `pattern` (e.g. `TASK-<number>`), and `type` (`list` → a YAML list).\n   - `relationships:` — these are the keys allowed under `links:`. Respect\n     `target` (the type each link must point to, or a subtype) and `min`/`max`\n     (e.g. `parent` is `max: 1`).\n4. **Allocate the id.** Scan existing files in the target `artifacts:` glob, find\n   the highest id matching the `pattern`, increment, and zero-pad to match\n   siblings.\n5. **Write the file** under the correct glob (`requirements/**`, `work/**`,\n   `tests/**`). Frontmatter: `type`, `id`, the required fields, then a `links:`\n   block keyed by relationship name with root-relative paths in lists:\n   ```yaml\n   links:\n     implements:  [/requirements/fr-0007.md]\n     parent:      [/work/story-0001.md]\n     verified_by: [/tests/test-orders.md]\n   ```\n6. **Validate.** Run `iBuild validate .` from the repo root (no path arg — the\n   linter prefixes `root` itself). If `summary.errors > 0`, read each finding's\n   `file`/`rule`/`message`, fix, and re-run. Done only at zero errors.\n\n## Verify a link before you write it\n\n`iBuild graph --node <target-ref>` confirms a target exists and shows its type, so\nyou wire `implements`/`verified_by`/`parent` to the right document.\n\n## Boundaries\n\n- One artifact per invocation. For a whole breakdown, use `/ibuild-plan`.\n- If the user asks for a type the profile does not define (e.g. an ADR when no ADR\n  type exists), either add an `ArtifactType` to `docs/types/` first, or write a\n  plain doc OUTSIDE the `artifacts:` globs — never emit frontmatter the dialect\n  cannot express just to fake it.\n- You write files; you do not `git add`/`commit`/`push`.\n- The linter is the authority. If it disagrees with you, it is right.\n",
  ".claude/skills/ibuild-bug/SKILL.md": "---\nname: ibuild-bug\ndescription: >\n  The bug workflow: capture a defect as a Bug artifact, reproduce it with a\n  failing regression test, find the root cause, fix it, then prove the fix —\n  wire the Bug's `affects` (the Requirement it violates) and `verified_by` (the\n  regression Test) and move it to `status: resolved`, but only once the test that\n  failed now passes. Use when the user says \"file a bug\", \"fix this bug\", \"log a\n  defect\", \"this is broken\", \"regression\", or names a BUG-id. Always finishes\n  with `iBuild validate`. Suggest-only: it never commits.\n---\n\n# iBuild Bug\n\nA defect is a violation of expected behaviour, so it lives in the same\ntraceability graph as the feature it broke. This workflow keeps it there: a Bug\nartifact `affects` the Requirement it violates and is `verified_by` a regression\nTest that fails before the fix and passes after. The linter is the authority — a\n`resolved` Bug should carry a `passing` regression test, or the graph is lying.\n\nIron law: **no fix without a reproduction.** A bug you cannot reproduce is a bug\nyou cannot prove you fixed.\n\n## Procedure\n\n1. **Locate the bundle.** Read `.ibuildos.yaml` → `root`, `types`, `artifacts`\n   globs, and the chain relationship names. Use these — never assume `docs/` or\n   hardcode a type name.\n2. **Capture the Bug.** Author a Bug artifact via the `/ibuild-author` dialect\n   discipline: id `BUG-<number>` (scan existing, increment), `status: open`,\n   `severity`, a body stating observed vs. expected behaviour and repro steps.\n   Link `affects` to the Requirement whose behaviour is violated (use\n   `iBuild graph --node <ref>` to find it); `parent` to an Epic if it groups one.\n   If no requirement covers the broken behaviour, say so — the \"bug\" may be a\n   missing requirement; route to `/ibuild-discover` / `/ibuild-plan`.\n3. **Reproduce.** Write a regression test that demonstrates the defect and **run\n   it** — confirm it FAILS, and fails for the right reason. No red test, no\n   confirmed bug.\n4. **Find the root cause.** Investigate until you can name the actual cause — not\n   a symptom. Do not patch around it. Set `status: in_progress`.\n5. **Fix.** Make the minimal code change that addresses the root cause, matching\n   surrounding style. Keep the diff scoped to this defect.\n6. **Prove it.** Re-run the regression test — it must now PASS — then run the full\n   test command (e.g. `go test ./...`, `npm test`) to confirm no new breakage.\n7. **Record the Test artifact.** Ensure a regression Test artifact exists (author\n   one if missing) and set its status to `passing` ONLY because you watched it go\n   green. Never set `passing` on faith.\n8. **Wire the proof.** On the Bug: add `verified_by` → the regression Test, confirm\n   `affects` is intact, set `status: resolved` (`wont_fix`/`closed` only when the\n   user decides not to fix).\n9. **Validate.** Run `iBuild validate .` from the repo root; fix every finding;\n   done only at zero errors.\n10. **Hand off.** Suggest `/ibuild-status` for coverage and `/ibuild-ship` for the\n    pre-merge gate. Do not commit or open a PR.\n\n## The honesty rule\n\n`status: resolved` claims the defect is gone and proven. The proof is the\nregression test that failed in step 3 and passes in step 6. If you never saw it\ngo red then green, the bug is not resolved — leave it `in_progress` and say why.\n\n## Boundaries\n\n- Bug has no `code` field — the proof is the regression `verified_by` Test, not\n  `code` globs. Do not invent frontmatter the Bug type does not define.\n- One defect per invocation. To implement a planned Task, use `/ibuild-implement`;\n  to write any single artifact's frontmatter, use `/ibuild-author`.\n- Never flip `status: resolved` while `iBuild validate` is red or the regression\n  test has not passed in this session.\n- You write code and artifacts; you do not `git add`/`commit`/`push`. Defer to the\n  user's ship flow.\n- The linter is deterministic and AI-free. This skill orchestrates it; it does not\n  replace it.\n",
  ".claude/skills/ibuild-contradict/SKILL.md": "---\nname: ibuild-contradict\ndescription: >\n  Find SEMANTIC contradictions across linked OKF-SDLC artifacts that the\n  deterministic linter cannot see — a Task whose body contradicts the requirement\n  it implements, two NonFunctionalRequirements in conflict, a Test asserting\n  behavior a Story forbids. Use when the user says \"check for contradictions\", \"do\n  these conflict\", \"semantic review\", \"do the tasks match their requirements\", or\n  \"review the content for consistency\". AI, suggest-only: it reports hypotheses\n  for human review and never rewrites anything.\n---\n\n# iBuild Contradict\n\nCatch conflicts in *meaning* across the typed graph — the layer the structural\nlinter can't reach. This is AI reasoning over content, so every finding is a\nconfidence-tagged hypothesis, never a verdict.\n\n## Procedure\n\n1. **Delegate to the checker subagent.** Launch the `ibuild-contradiction-checker`\n   agent. It reads the link graph (`iBuild graph --body full`) and the bodies of\n   linked artifact pairs, then reports possible contradictions.\n2. **Present the report** to the user: each conflict names the two artifacts, the\n   relationship between them, the clashing claims (quoted), and a suggestion or a\n   \"needs human ruling\".\n3. **Resolve with the user.** A contradiction is a judgment call. If the user\n   decides which side changes, route the edit through `/ibuild-author` and re-run\n   `iBuild validate .`. Never pick a winner yourself.\n\n## Boundaries\n\n- Suggest-only. The checker never edits a file, resolves a conflict, or commits —\n  an AI silently rewriting the source of truth is the failure mode this design\n  exists to avoid.\n- Findings are \"possible\", not \"definite\". Tag confidence and let the human rule.\n- This is orthogonal to `/ibuild-audit`: that finds structural gaps, this finds\n  semantic conflicts. Run both for a full review.\n",
  ".claude/skills/ibuild-discover/SKILL.md": "---\nname: ibuild-discover\ndescription: >\n  Turn a raw idea into the top of the OKF-SDLC chain: a Vision, a PRD, and one or\n  more BusinessRequirement artifacts, correctly linked. This is the \"why\" before\n  any work breakdown. Use when the user says \"I have an idea\", \"capture this\n  product\", \"write the vision/PRD\", \"what are the requirements\", or is starting a\n  new initiative and needs the problem framed as artifacts. Hands off to\n  /ibuild-plan for the work breakdown.\n---\n\n# iBuild Discover\n\nCapture intent at the top of the chain. Interview lightly, then write artifacts —\ndo not over-produce. Each file conforms to its type definition in `docs/types/`.\n\n## Procedure\n\n1. **Locate the bundle** (read `.ibuildos.yaml`). If there is no bundle yet, run\n   `/ibuild-init` first.\n2. **Understand the idea.** Ask only what you need: the problem, who has it, and\n   what success looks like. Keep it to a few questions.\n3. **Write top-of-chain artifacts**, each via the same dialect discipline as\n   `/ibuild-author` (read the type def, supply required fields, valid id, links):\n   - one **Vision** — the long-term \"why\".\n   - one **PRD** — the product definition, linked to the Vision.\n   - one or more **BusinessRequirement** — the concrete needs, linked to the PRD\n     (use the relationship the PRD/requirement types declare, e.g. `traces_to`).\n   Only create what the idea justifies — a small idea may be a single BR.\n4. **Validate.** Run `iBuild validate .`; fix findings; reach zero errors.\n5. **Hand off.** Suggest `/ibuild-plan` to refine these into FR/NFR and break the\n   work down.\n\n## Boundaries\n\n- Don't fabricate scope. If the user hasn't decided something, leave it out or ask\n  — an empty-but-honest bundle beats a confident-but-wrong one.\n- Suggest-only on anything ambiguous; you write artifacts, you don't commit.\n- Defer to `iBuild validate`.\n",
  ".claude/skills/ibuild-explore/SKILL.md": "---\nname: ibuild-explore\ndescription: >\n  A no-stakes thinking partner before any change is proposed: read the existing\n  graph, weigh options, and map the blast radius of an idea — which requirements\n  it would ADD, MODIFY, or REMOVE, and which work it would touch. Use when the\n  user says \"explore\", \"what would it take to…\", \"I'm thinking about changing…\",\n  \"what does this affect\", or is sizing up an evolution before committing. Writes\n  nothing — it ends by recommending /ibuild-propose with a concrete change shape.\n---\n\n# iBuild Explore\n\nThe cheap, reversible step before a Change exists. You investigate and shape a\ndirection; you do not author artifacts. The deliverable is a clear-eyed proposal\nthe user can accept into `/ibuild-propose`.\n\n## Procedure\n\n1. **Locate the bundle** (read `.ibuildos.yaml` → `root`, `types`, `artifacts`,\n   chain relationship names). Never assume `docs/` or hardcode a type name.\n2. **Understand the intent.** Ask only what you need to size the change.\n3. **Map the blast radius from the graph, not from guessing.** Run\n   `iBuild graph . --format json`; for a specific artifact use\n   `iBuild graph --node <ref> --depth 1`. Identify:\n   - which existing **Requirements** the idea would **MODIFY** or **REMOVE**\n     (and the work `implements`-linked to them that would move with them),\n   - what new behaviour would need to be **ADDED** as new requirements,\n   - the Tasks/Stories/Tests already in the neighborhood.\n4. **Weigh options.** Sketch one or two ways to do it, with trade-offs. Name the\n   smallest version that delivers value.\n5. **Recommend a change shape** — the scope (`added`/`modified`/`removed`/`mixed`),\n   the requirements it `affects`, and a rough task list — and hand off to\n   `/ibuild-propose` to capture it. Note that `iBuild instructions Change` gives\n   the exact fields when the user is ready.\n\n## Boundaries\n\n- Read-only. No artifacts, no edits, no commits — exploring is free precisely\n  because nothing is written.\n- Derive impact from `iBuild graph`; if you can't see it in the graph, say so.\n- One idea per pass. Capture happens in `/ibuild-propose`, breakdown in\n  `/ibuild-plan`.\n",
  ".claude/skills/ibuild-impact/SKILL.md": "---\nname: ibuild-impact\ndescription: >\n  Change-impact analysis for an OKF-SDLC bundle: given files you changed (or your\n  working-tree diff), show which Tasks, Requirements, and Tests the change\n  touches, derived deterministically from the typed link graph. Use when the user\n  says \"what does this change affect\", \"blast radius\", \"impact of editing X\", or\n  before refactoring code that has linked tasks. Read-only; it runs the\n  deterministic `iBuild impact` and explains the result — it changes nothing.\n---\n\nYou answer \"what does this change touch?\" using the deterministic engine, not a\nguess. The `iBuild impact` command walks the resolved graph: a changed code file\nis matched against every Task's `code` globs, and from each affected Task it\nfollows `implements` to requirements, `verified_by` to tests, and `parent` to the\nowning work.\n\n## How to run\n\n1. Read `.ibuildos.yaml` for the bundle layout.\n2. Run the deterministic command (it is AI-free and exact):\n   - `iBuild impact <file> [<file>…]` for specific files, or\n   - `iBuild impact --changed` to use your git working-tree changes.\n   It prints JSON: `{ changed, affectedTasks, affectedRequirements, affectedTests, affectedParents }`.\n3. Cross-check with `iBuild graph --node <task> --depth 1` if you want the\n   surrounding neighborhood of an affected task.\n\n## What to report\n\n- The affected Tasks, and for each, the Requirement(s) it implements and the\n  Test(s) that verify it — so the user sees the full blast radius.\n- Tests that should be re-run (the `affectedTests`).\n- Requirements whose acceptance might change — flag these for human review.\n\n## Hard rules\n\n- Read-only. You run `iBuild impact`/`iBuild graph` and explain; you never edit\n  artifacts or code, and you never commit.\n- The command is deterministic — report its output faithfully; do not invent\n  links it did not find.\n",
  ".claude/skills/ibuild-implement/SKILL.md": "---\nname: ibuild-implement\ndescription: >\n  Implement a Task (or every Task under a Story/Epic): write the real application\n  code and tests, run the project's test command, then wire the Task's `code`\n  globs and `verified_by` link and flip it to `status: done` — but only once the\n  code exists and the tests actually pass. Closes the Requirement→Task→Code→Test\n  chain that /ibuild-plan and /ibuild-author opened. Use when the user says\n  \"implement TASK-0007\", \"build this story\", \"do the work for this epic\", \"write\n  the code for this task\", or \"make this task done\". Always finishes with\n  `iBuild validate`. Suggest-only: it never commits.\n---\n\n# iBuild Implement\n\nTurn a planned Task into shipped, proven work. iBuildOS plans and proves\ntraceability; it does not generate your app code — that is normal coding. This\nskill couples the two: write the code, run the tests, then make the artifact tell\nthe truth. The linter is the authority — a `done` Task must have `code` globs that\nmatch real files and a `verified_by` test that is `passing`, or `iBuild validate`\ngoes red.\n\n## Procedure\n\n1. **Locate the bundle.** Read `.ibuildos.yaml` → `root`, `types`, `artifacts`\n   globs, and the chain field/relationship names (`code_field`, `implements`,\n   `verified_by`, `parent`). Use these — never assume `docs/` or hardcode a type\n   name.\n2. **Resolve the target.** `iBuild graph --node <ref> --depth 1` shows the\n   artifact, its type, and what it links to.\n   - A **leaf work item** (a Task/Subtask — concrete, no children): implement it.\n   - A **container** (a Story/Epic with `parent` children): list its children and\n     implement each leaf Task in dependency order. Confirm the set with the user\n     before a large batch.\n3. **Understand the intent.** Read the Task body, the requirement it `implements`\n   (directly or via its parent), and the parent Story for acceptance criteria.\n   Do not invent scope the chain does not justify — ask if unclear.\n4. **Write the code.** Implement the change as ordinary code in the repo, matching\n   the surrounding style. Keep the diff scoped to this Task.\n5. **Write and run the test.** Add or extend the real test that exercises the\n   change, then **run the project's test command** (e.g. `go test ./...`, `npm\n   test`). The test must actually pass. If it fails, fix the code — do not proceed.\n6. **Record the Test artifact.** Ensure a Test artifact exists for this work\n   (author one via the `/ibuild-author` dialect discipline if missing) and set its\n   status to `passing` ONLY because you watched the suite go green. Never set\n   `passing` on faith.\n7. **Wire the proof on the Task.** Set the `code` field to glob(s) that match the\n   files you wrote, add the `verified_by` link to the Test artifact, confirm the\n   `implements`/`parent` trace is intact, and set `status: done`.\n8. **Validate.** Run `iBuild validate .` from the repo root. If\n   `summary.errors > 0`, read each finding (`file`/`rule`/`message`) and fix —\n   usually a `code` glob that matches nothing, a test that is not `passing`, or a\n   missing requirement trace. Done only at zero errors.\n9. **Hand off.** Suggest `/ibuild-status` for coverage and `/ibuild-ship` for the\n   pre-merge gate. Do not commit or open a PR.\n\n## The honesty rule\n\n`status: done` is a claim that the work is real and verified. The gate checks the\n`code` globs match files and the test is `passing`, but it trusts *you* that the\nsuite truly ran green. Run it. A Task that compiles but whose test you never\nexecuted is not done — leave it `in_progress` and say so.\n\n## Boundaries\n\n- Implement only what the target Task scopes. For more work, plan it first with\n  `/ibuild-plan`; for a single artifact's frontmatter, use `/ibuild-author`.\n- Never flip `status: done` while `iBuild validate` is red or the test command\n  has not passed in this session.\n- You write code and artifacts; you do not `git add`/`commit`/`push`. Defer to the\n  user's ship flow.\n- The linter is deterministic and AI-free. This skill orchestrates it; it does not\n  replace it.\n",
  ".claude/skills/ibuild-init/SKILL.md": "---\nname: ibuild-init\ndescription: >\n  Set up the current project as an iBuildOS OKF-SDLC bundle so requirements,\n  work, and tests live in git as validated artifacts. Runs `iBuild init`, which\n  scaffolds .ibuildos.yaml, the docs/types/ profile, the bundle directories, a\n  starter CLAUDE.md, the develop-with-iBuildOS guide, and a vendored .claude/\n  (the iBuild skills + auditor/contradiction-checker agents + validate-on-edit\n  hook) so the repo is self-contained — then confirms the bundle validates. Use\n  when the user says \"set up iBuildOS\", \"init the bundle\",\n  \"add OKF-SDLC to this repo\", \"start managing requirements here\", or is starting\n  a new project and wants the requirements/planning workflow.\n---\n\n# iBuild Init\n\nMake this repo iBuildOS-native: a deterministic gate (`iBuild validate`) plus the\nauthoring skills, with git as the single source of truth.\n\n## Procedure\n\n1. **Check for `iBuild`.** Run `iBuild version`. If it is not on PATH, tell the\n   user to build it (`go build -o iBuild ./cmd/iBuild` from the iBuildOS repo, or\n   install the release) and stop — every other skill depends on it.\n2. **Check for an existing bundle.** If `.ibuildos.yaml` already exists, say so;\n   `iBuild init` is idempotent and will only add missing files, never overwrite.\n3. **Scaffold.** Run `iBuild init .` (add `--example` if the user wants a sample\n   requirement to see the shape). Show the created-files summary.\n4. **Confirm the gate.** Run `iBuild validate .` and confirm it exits 0 — an\n   empty bundle is a valid bundle.\n5. **Point the way.** Tell the user the lifecycle and the next step:\n   - capture an idea → `/ibuild-discover`\n   - plan and break down work → `/ibuild-plan`\n   - write one artifact → `/ibuild-author`\n   The full walkthrough is in `docs/develop-with-ibuildos.md`.\n   Note the vendored `.claude/` now ships the iBuild skills/agents into this\n   repo — they work on clone without a marketplace install. Suggest committing it.\n\n## Boundaries\n\n- `iBuild init` never overwrites; if a file conflicts it is left untouched and the\n  user merges manually. Do not force or delete anything.\n- You scaffold; you do not `git add`/`commit`. Let the user commit.\n- The linter is deterministic and AI-free. This skill only runs it.\n",
  ".claude/skills/ibuild-plan/SKILL.md": "---\nname: ibuild-plan\ndescription: >\n  Refine requirements and break work down: turn BusinessRequirements into\n  Functional/NonFunctional requirements, then decompose\n  Initiative→Epic→Story→Task→Subtask with parent and implements links, and plan\n  cadence with Release/Sprint/Milestone. Use when the user says \"break this\n  down\", \"plan the epic\", \"split into stories/tasks\", \"create the backlog\",\n  \"plan a release/sprint\", or \"what work does this need\". Builds the middle of the\n  chain so /ibuild-author and /ibuild-audit have something to trace.\n---\n\n# iBuild Plan\n\nDecompose work into linked OKF-SDLC artifacts so the chain is traceable end to\nend. Produce several artifacts in one pass, each conforming to its type def.\n\n## Procedure\n\n1. **Locate the bundle and the starting point.** Read `.ibuildos.yaml`. Identify\n   the requirement(s) or initiative the user is planning from. `iBuild graph\n   --node <ref>` shows what already links to it so you don't duplicate work.\n2. **Refine requirements.** From each BusinessRequirement, derive\n   **FunctionalRequirement** and **NonFunctionalRequirement** artifacts, linked\n   back (e.g. `derives_from`/`traces_to` as the types declare).\n3. **Break down the work**, climbing the hierarchy the types define:\n   - **Initiative → Epic → Story → Task → Subtask**, each new artifact's `parent`\n     pointing one level up (`parent` is `max: 1`).\n   - Work that fulfills a requirement gets an `implements` link to it (directly,\n     or the Story implements it and the Tasks roll up via `parent`).\n   - **Bug** / **Spike** sit as peers of Story under an Epic.\n4. **Plan cadence (optional).** Link backlog items to a **Release**\n   (`planned_for`) and a **Sprint** (`scheduled_in`); a **Milestone** may\n   `require` work; a **Roadmap** may `include` initiatives.\n5. **Honor the dialect** for every file (required fields, id `pattern`, link\n   `target`/`min`/`max`), exactly as `/ibuild-author` does. When writing many\n   files, keep ids consistent and sequential.\n6. **Validate.** Run `iBuild validate .`; fix findings; reach zero errors. A\n   `proposed` requirement with nothing implementing it is a *warning*, not an\n   error — fine while planning.\n\n## Keep it honest\n\n- Decompose only as far as the user actually wants. Don't invent tasks to fill a\n  template — a thin, true breakdown beats a thick, speculative one.\n- Wire links as you go; a broken graph that \"looks complete\" is worse than an\n  honestly-partial one. `iBuild validate` will tell you which links dangle.\n\n## Boundaries\n\n- You write artifacts; you do not commit.\n- The completeness rules (`iBuild validate`) are the authority on whether the\n  chain is whole.\n",
  ".claude/skills/ibuild-propose/SKILL.md": "---\nname: ibuild-propose\ndescription: >\n  Capture a proposed evolution as a Change artifact — the why, the what/scope, and\n  the requirements it affects — at status:proposed, plus any new requirements it\n  ADDS (at status:proposed). This is the spec-driven \"agree before you build\" step.\n  Use when the user says \"propose a change\", \"write this up\", \"draft a proposal\",\n  \"let's plan this change\", or accepts an idea from /ibuild-explore. Always finishes\n  with `iBuild validate`. Suggest-only: it never commits.\n---\n\n# iBuild Propose\n\nA Change is the unit of evolution — one artifact that captures intent so humans\nand AI agree on the plan before code. The Change is a graph node, not a folder:\ngit stays the source of truth; the Change makes the *requirement delta* reviewable\nand linkable in a way a raw diff isn't.\n\n## Procedure\n\n1. **Locate the bundle** (read `.ibuildos.yaml`). Confirm a `Change` type exists\n   (`iBuild instructions Change`); if not, the profile predates this overlay —\n   tell the user.\n2. **Get the exact fields.** Run `iBuild instructions Change` for the required\n   frontmatter, id pattern (`CHANGE-<slug>`), the `status`/`scope` enums, and the\n   `affects`/`delivers`/`supersedes` links. Never hardcode field knowledge.\n3. **Author the Change** under the changes glob (e.g. `docs/changes/CHANGE-<slug>.md`),\n   `status: proposed`, with a body that captures:\n   - `## Why` — the problem and the user need,\n   - `## What changes` — scope in/out; set the `scope` field\n     (`added`/`modified`/`removed`/`mixed`),\n   - `## Design` — the technical approach and key decisions.\n4. **Wire the delta** with `affects` links, expressing each kind the iBuildOS way:\n   - **ADDED** — author the new requirement(s) at `status: proposed` (via the\n     `/ibuild-author` dialect discipline) and link them under `affects`.\n   - **MODIFIED / REMOVED** — link the existing requirement(s) under `affects`;\n     leave them as-is for now (status changes happen in `/ibuild-apply`).\n   Use `iBuild graph --node <ref>` to find the requirements involved.\n5. **Validate.** Run `iBuild validate .`; fix findings; reach zero errors. A\n   proposed requirement with no implementer is a warning, not an error — expected\n   at this stage.\n6. **Hand off.** Suggest `/ibuild-apply` to break the change down and build it.\n\n## Boundaries\n\n- Don't break work down here — that's `/ibuild-apply` → `/ibuild-plan`. Propose\n  captures intent and the requirement delta only.\n- A Change draws no chain-completeness findings; it's capture, not a gate. Don't\n  invent frontmatter the type doesn't define.\n- Suggest-only. You author artifacts; you don't `git commit`.\n",
  ".claude/skills/ibuild-ship/SKILL.md": "---\nname: ibuild-ship\ndescription: >\n  The traceability gate before shipping: confirm `iBuild validate` is clean and\n  the Requirement→Task→Code→Test chain is complete, surface anything blocking,\n  then hand off to the project's normal PR/ship flow. Use when the user says\n  \"ship\", \"is this ready\", \"ready to merge\", \"ship the requirements\", or \"gate\n  this\". It validates and reports; it does not invent a git workflow.\n---\n\n# iBuild Ship\n\nThe last check before work leaves the branch: the deterministic gate must be green\nand the chain whole.\n\n## Procedure\n\n1. **Run the gate.** `iBuild validate .` must exit 0. If it doesn't, stop and route\n   the user to `/ibuild-audit` — do not ship a red bundle.\n2. **Check chain completeness** with `/ibuild-status` (or `iBuild graph`): no\n   `done` task missing code or a passing test, no active requirement\n   unimplemented/untested. Warnings (e.g. a `proposed` requirement) are not\n   blockers — call them out but don't gate on them.\n3. **Optionally** suggest `/ibuild-contradict` for a semantic pass if the change\n   touched requirement or task content.\n4. **Hand off to the real ship flow.** If the project has a `/ship` skill or a\n   documented PR process, use it. iBuildOS gates traceability; it does not replace\n   your git/PR tooling. Do not push or open a PR unless the user asks.\n\n## Boundaries\n\n- Gate, don't bypass: never mark work shippable while `iBuild validate` is red.\n- You do not `git commit`/`push`/open PRs on your own — confirm with the user and\n  defer to their ship flow.\n",
  ".claude/skills/ibuild-status/SKILL.md": "---\nname: ibuild-status\ndescription: >\n  Show a traceability dashboard for the OKF-SDLC bundle, derived from `iBuild\n  graph` — chain completeness, unimplemented or untested requirements, orphan\n  tasks, code/test coverage, and work rolled up by Release/Epic. Use when the user\n  says \"status\", \"where are we\", \"traceability dashboard\", \"what's left\", \"show\n  the graph\", \"coverage\", or \"health of the bundle\". Read-only — it reports, it\n  doesn't change anything. State lives in git, not a sidecar.\n---\n\n# iBuild Status\n\nA live picture of the bundle, computed from the artifacts in git. No external\ntracker, no hidden state — `iBuild graph` is the whole knowledge graph.\n\n## Procedure\n\n1. **Locate the bundle** (read `.ibuildos.yaml`).\n2. **Pull the graph.** Run `iBuild graph . --format json` (add `--body none` for a\n   compact pass). The `types` block tells you which relationships matter\n   (`implements`, `verified_by`, `parent`); the `nodes`/`edges` are the data.\n3. **Run the gate for the headline.** `iBuild validate . --format json` gives the\n   authoritative error/warning counts. Lead with those.\n4. **Summarize**, deriving from the graph (not by guessing):\n   - **Requirements**: how many, how many implemented (have an incoming\n     `implements` edge), how many verified (incoming `verifies`/`verified_by`).\n     List the unimplemented/untested ones by id.\n   - **Work**: tasks by status; `done` tasks missing code or a passing test;\n     orphan tasks (no `parent`, no `implements`).\n   - **Coverage**: roll work up by `parent` to Epic/Story, and by `planned_for`\n     to Release, if those links exist.\n   - **Changes** (if the profile has a `Change` type): for each Change, its\n     `status` and progress — count `delivers` Tasks that are `done` over the\n     total, e.g. `CHANGE-orders-freshness-sla: active — 2/4 tasks done`. This is\n     a pure derivation from the graph; it computes no findings and gates nothing.\n   - **Dangling links**: edges with `resolved: false`.\n5. **Present** a short, scannable dashboard. Point the user at `/ibuild-audit` to\n   fix structural gaps or `/ibuild-contradict` for semantic ones.\n\n## Fast lookups\n\n`iBuild graph --node <ref> --depth 1` answers \"what touches this artifact\" in one\ncall — use it when the user asks about a specific requirement or task.\n\n## Boundaries\n\n- Read-only. Never edit or commit.\n- Numbers come from `iBuild graph`/`iBuild validate`, not from prose inference —\n  if you can't derive it from the graph, say so.\n",
  "CLAUDE.md": "# CLAUDE.md\n\nThis project uses **iBuildOS** — a Git-native SDLC layer on OKF. The whole\nlifecycle (requirements, work breakdown, tests, releases) lives under `docs/` as\nOKF artifacts: markdown files with YAML frontmatter and typed links, validated by\nthe deterministic `iBuild` linter. **Git is the source of truth** — there is no\nexternal tracker, and no hidden state.\n\n## Develop with iBuildOS\n\nFull walkthrough: `docs/develop-with-ibuildos.md`. The lifecycle and the skill for\neach stage:\n\n| Stage | Want to… | Skill |\n|---|---|---|\n| Discover | capture an idea as Vision → PRD → BusinessRequirement | `/ibuild-discover` |\n| Plan | refine into FR/NFR and break down Initiative→Epic→Story→Task | `/ibuild-plan` |\n| Build | write one artifact correctly (any of the project's types) | `/ibuild-author` |\n| Implement | write code + tests for a Task/Story and close the chain | `/ibuild-implement` |\n| Fix | file, reproduce, root-cause, and fix a bug | `/ibuild-bug` |\n| Review | check traceability and find chain gaps | `/ibuild-audit` |\n| Review | find semantic contradictions across linked artifacts | `/ibuild-contradict` |\n| Monitor | see the traceability dashboard | `/ibuild-status` |\n| Ship | validate-and-ship | `/ibuild-ship` |\n\n**Changing an existing system?** (Needs the full profile — `iBuild init --full`, or\nadd `change.md`/`scenario.md` to `docs/types/`.) Capture it as a `Change` and run the\noverlay: `/ibuild-explore` (map the blast radius) → `/ibuild-propose` (author the\nChange + the requirements it affects) → `/ibuild-apply` (break down + implement) →\n`/ibuild-archive` (gate clean → `status: archived`). A Change is a graph node, not a\nfolder; git stays the source of truth. Use `Scenario` artifacts for GIVEN/WHEN/THEN\nacceptance criteria in RFC 2119 language.\n\nThe skills are vendored in `.claude/` (committed with this repo), so they work on\nclone with no install. To also install them machine-wide: `/plugin marketplace add\nPurnaOS/iBuildOS` then `/plugin install ibuildos`.\n\nFast knowledge (for you or an agent): `iBuild graph --node /work/task-0001.md`\nreturns a node and its neighborhood; `iBuild instructions <Type>` prints the exact\nauthoring template for a type (from `docs/types/`).\n\n## The gate\n\n`iBuild validate .` must exit 0 before shipping. The AI skills suggest and edit;\nthey never auto-commit and they never run inside the linter. A `Task` may be\n`status: done` only once its `code` globs match real files, its `verified_by`\ntests are `passing`, and it traces to a requirement (directly or via its parent).\n",
  "docs/changes/.gitkeep": "",
  "docs/develop-with-ibuildos.md": "---\ntype: Reference\ntitle: Develop a New Project with iBuildOS\ndescription: The end-to-end lifecycle — from idea to shipped, traceable work — using OKF-SDLC artifacts and the iBuild gate.\ntags: [guide, lifecycle, okf, sdlc]\n---\n\n# Develop a New Project with iBuildOS\n\niBuildOS turns your repo into the single source of truth for the whole SDLC. You\nwrite requirements and plan work as **OKF artifacts** (markdown + YAML frontmatter\nwith typed links); the deterministic **`iBuild`** linter checks the\nRequirement→Task→Code→Test chain; and a set of Claude Code skills do the authoring\nwith you. AI **suggests and edits — it never auto-commits and never runs inside the\nlinter.**\n\nThis is the path, in the order you actually type it.\n\n## 0. Set up (once)\n\n```bash\niBuild init .            # scaffolds .ibuildos.yaml, docs/types/, the bundle dirs,\n                         # AND a vendored .claude/ (the skills + agents + the\n                         # validate-on-edit hook)\niBuild validate .        # exits 0 — an empty bundle is a valid bundle\n```\n\nBy default `init` writes the **lean core profile**: just the\nRequirement → Task → Code → Test chain plus Story and Bug (7 types). When you need\nthe full taxonomy — Vision/PRD, the Business/Functional/NonFunctional split,\nInitiative/Epic, planning (Release/Sprint/Milestone/Roadmap), Spike/Persona, and the\nChange/Scenario overlay — run `iBuild init --full`. The profile is pure data: you\ncan also start lean and add any type later by dropping its `*.md` into `docs/types/`.\n\n`iBuild init` vendors the skills into `.claude/`, so a clone of this repo is\nself-contained — every `/ibuild-*` command works with **no install**. (You can\nalso install them machine-wide as a plugin: `/plugin marketplace add\nPurnaOS/iBuildOS` then `/plugin install ibuildos`.) Commit `.claude/` so your\nteam gets the same workflow.\n\n## 1. Discover — idea → Vision / PRD / BusinessRequirement\n\n```\n/ibuild-discover\n```\nTurns a raw idea into the top of the chain: a **Vision**, a **PRD**, and one or more\n**BusinessRequirement** artifacts, linked. This is your \"why\".\n\n## 2. Plan — requirements and a work breakdown\n\n```\n/ibuild-plan\n```\nRefines business needs into **FunctionalRequirement** / **NonFunctionalRequirement**\nartifacts, then decomposes the work: **Initiative → Epic → Story → Task → Subtask**,\nwith `parent` links climbing the hierarchy and `implements` links tracing work back\nto the requirement it satisfies. Plan cadence with **Release** / **Sprint** when you\nwant it (`planned_for`, `scheduled_in`).\n\n## 3. Build — author artifacts\n\n```\n/ibuild-author\n```\nWrites one artifact at a time, correctly: it reads the type definition in\n`docs/types/` so it always supplies the required fields, a valid id, and the right\ntyped links. Use it whenever you need a single, conformant artifact.\n\n## 4. Implement — write the code and close the chain\n\n```\n/ibuild-implement        # e.g. \"implement TASK-0007\" or \"build this story\"\n```\niBuildOS plans and *proves* traceability; it does not generate your app code —\nthat's normal coding. This skill couples the two: it reads the Task (and the\nrequirement it implements), writes the real code and tests, **runs the test\ncommand**, then wires the Task's `code:` globs and `verified_by` Test and flips it\nto `status: done`. The honesty rule: `done` only after the suite actually goes\ngreen — the gate refuses a `done` Task whose `code` matches nothing or whose Test\nisn't `passing`.\n\n## 5. Fix — the bug workflow\n\n```\n/ibuild-bug              # \"file a bug\", \"fix this bug\", or a BUG-id\n```\nA defect lives in the same graph as the feature it broke. This workflow captures a\n**Bug** that `affects` the violated Requirement, reproduces it with a regression\ntest that **fails first**, finds the root cause (no fix without a reproduction),\nfixes it, then proves the fix — the regression Test goes green, gets wired as\n`verified_by`, and the Bug moves to `status: resolved`. Bug has no `code` field;\nthe proof *is* the regression test.\n\n## 6. Review — gaps and contradictions\n\n```\n/ibuild-audit        # structural: runs iBuild validate, finds chain gaps, proposes fixes\n/ibuild-contradict   # semantic: AI finds conflicts across linked artifacts\n```\nThe auditor is deterministic-first — the linter is the authority; it adds the human\n\"why\" and concrete edit proposals. The contradiction-checker reads the linked bodies\nand flags conflicts the linter can't see (a Task that contradicts its requirement,\ntwo NFRs that fight). Both **propose only** — you approve and apply.\n\n## 7. Monitor — the traceability dashboard\n\n```\n/ibuild-status\n```\nRenders chain health from `iBuild graph`: which requirements are unimplemented or\nuntested, which Tasks are orphaned, coverage rolled up by Release/Epic. No sidecar\nstate — it's all derived from the artifacts in git.\n\n## 8. Ship\n\n```\n/ibuild-ship\n```\nThe gate: `iBuild validate .` must be clean and the chain complete before the work\nbecomes a PR.\n\n## 9. Evolve — the change overlay (brownfield, full profile)\n\nThe `Change` and `Scenario` types live in the **full profile** (`iBuild init --full`,\nor add `change.md`/`scenario.md` to `docs/types/`). Greenfield runs\ndiscover→plan→implement. When you're *changing* a system that already exists,\ncapture the evolution as a **Change** and run it through its own lifecycle:\n\n```\n/ibuild-explore      # read-only: what would this touch? (ADD / MODIFY / REMOVE)\n/ibuild-propose      # author the Change (why/what/scope) + the requirements it affects\n/ibuild-apply        # activate, break down, implement, settle the delta\n/ibuild-archive      # gate clean + work done → status: archived\n```\n\nA Change is a graph node, not a folder — git stays the source of truth, and the\nChange is the reviewable, linkable record of intent a raw diff isn't. The delta\nmaps onto mechanics you already have: **ADDED** = a new `proposed` requirement,\n**MODIFIED** = edit in place (git is the diff), **REMOVED** = `status: deprecated`.\nA Change draws no chain-completeness findings — it's capture, not a new gate.\n\nFor precise acceptance criteria, author a **Scenario**: one GIVEN/WHEN/THEN\ncondition in RFC 2119 language (SHALL/MUST/SHOULD/MAY). Because a Scenario\n`verifies` a Requirement, it counts toward chain completeness exactly like a Test.\nFor quick inline definition-of-done, use the `acceptance_criteria` list on a Story.\n\n```bash\niBuild instructions Change      # the exact authoring template for any type,\niBuild instructions             # …or list every type. Derived from docs/types/.\n```\n\n## Fast knowledge — the graph is your \"code graph\"\n\n`iBuild graph` is to your artifacts what a source-code graph (ctags/LSIF) is to\ncode: a precomputed, typed map you query in one call instead of grepping markdown.\n\n```bash\niBuild graph .                                   # whole graph as JSON\niBuild graph --node /requirements/fr-0001.md     # one node + its neighbors\niBuild graph --node /work/task-0001.md --depth 2 --rel implements,verified_by\n```\n\n## The rules that keep the graph honest\n\n- Every artifact conforms to its type definition in `docs/types/` — edit those to\n  change your process; the linter follows with zero code change.\n- Links are typed: a relationship names a `target` type and a cardinality.\n- A **Task** is `status: done` only once its `code` globs match real files, its\n  `verified_by` Test is `passing`, and it traces to a requirement.\n- `iBuild validate .` exits 0 is the definition of \"done enough to ship.\"\n",
  "docs/requirements/.gitkeep": "",
  "docs/scenarios/.gitkeep": "",
  "docs/tests/.gitkeep": "",
  "docs/work/.gitkeep": "",
  "ibuildos.yaml": "# iBuildOS bundle config. The knowledge bundle is rooted at docs/; only files\nprofile:\n  name: ibuildos-base\n  version: 0.5.0\n# matched by the artifacts globs are strict-validated. Type definitions live in\n# docs/types/ and define the whole SDLC taxonomy as data — edit them to fit your\n# process and `iBuild validate` follows with zero code change.\nroot: docs\ntypes: types\nartifacts:\n  - requirements/**\n  - work/**\n  - tests/**\n  - changes/**\n  - scenarios/**\ncode_field: code\n",
  "profiles/core/artifact-type.md": "---\ntype: ArtifactType\ndefines: ArtifactType\ndescription: The meta-type. Defines the structure every type definition follows.\nfields:\n  defines:\n    required: true\n    doc: The name of the type this document defines.\n  extends:\n    doc: Optional parent type whose fields and relationships are inherited.\n  abstract:\n    type: bool\n    doc: If true, no document may use this type directly; it exists only to be extended.\n  description:\n    doc: One-line summary of the artifact type.\n  fields:\n    doc: Map of field name to field spec (see body).\n  relationships:\n    doc: Map of relationship name to relationship spec (see body).\n---\n\n# ArtifactType\n\nAn **ArtifactType** defines one kind of artifact in the project — a Task, a\nRequirement, an ADR, and so on. It is the *only* type the validator understands\nnatively. Every other type is just data written in this format, which is why a\nproject can define its own lifecycle without changing a line of the tool's code.\n\n`ArtifactType` is itself an `ArtifactType` (this document), so the engine\nvalidates type definitions with the same machinery it uses on everything else.\n\n## Field spec\n\nEach entry under `fields:` describes one frontmatter key that documents of this\ntype may carry.\n\n| Key        | Meaning                                                                                   |\n|------------|-------------------------------------------------------------------------------------------|\n| `required` | `true` if the field must be present. Default `false`.                                     |\n| `one_of`   | List of allowed values (an enum).                                                         |\n| `pattern`  | A string pattern. Friendly tokens: `<number>`, `<slug>`, `<date>`. Use `regex:...` raw.   |\n| `type`     | `string` (default), `number`, `date`, or `bool`.                                          |\n| `doc`      | Human description of the field.                                                           |\n\n## Relationship spec\n\nEach entry under `relationships:` declares a typed link. In an actual document\nthese appear under a `links:` block, keyed by the relationship name.\n\n| Key      | Meaning                                                          |\n|----------|------------------------------------------------------------------|\n| `target` | The artifact type every link under this name must point to.      |\n| `min`    | Minimum number of links required. Default `0`.                   |\n| `max`    | Maximum number of links allowed. Optional (unbounded if absent). |\n| `doc`    | Human description of the relationship.                           |\n\nA link satisfies `target: X` if the document it points to has type `X` **or any\ntype that extends `X`**. So a relationship whose `target` is an abstract base —\ne.g. `Requirement` or `BacklogItem` — is satisfied by any of its concrete\nsubtypes.\n\n## Escape hatch\n\nFor validation the tiny dialect can't express, a definition may include a\n`json_schema:` block. It is applied to a document's frontmatter *in addition to*\nthe rules above, so power users get full JSON Schema without forcing everyone\nelse to read it.\n\n## Example\n\nSee [Task](task.md) for a complete definition and the document it validates.\n",
  "profiles/core/bug.md": "---\ntype: ArtifactType\ndefines: Bug\nextends: WorkItem\ndescription: A defect — behaviour that violates a requirement.\nfields:\n  id:\n    required: true\n    pattern: \"BUG-<number>\"\n    doc: Stable identifier, e.g. BUG-417.\n  status:\n    required: true\n    one_of: [open, in_progress, resolved, closed, wont_fix]\n    doc: Current state.\n  severity:\n    one_of: [blocker, critical, major, minor, trivial]\n    doc: Impact severity. Optional.\nrelationships:\n  affects:\n    target: Requirement\n    doc: The requirement(s) whose behaviour is violated.\n  verified_by:\n    target: Test\n    doc: Regression test(s) proving the fix.\n  parent:\n    target: WorkItem\n    max: 1\n    doc: Optional parent for grouping.\n---\n\n# Bug\n\nA **Bug** keeps a defect in the same graph as the feature it broke: it `affects`\nthe [Requirement](requirement.md) it violates and is `verified_by` a regression\n[Test](test.md) that fails before the fix and passes after. A `resolved` Bug\nshould carry a `passing` test, or the graph is lying.\n",
  "profiles/core/index.md": "# Artifact Types — core profile\n\nThe lean SDLC profile: the **Requirement → Task → Code → Test** chain and a couple\nof common helpers. Each file is an `ArtifactType` document whose frontmatter drives\nthe validator — edit them and the linter follows with zero code change.\n\n# Meta & base\n\n* [ArtifactType](artifact-type.md) - the meta-type; defines the dialect itself\n* [WorkItem](work-item.md) - abstract base: id, title, owner, status\n\n# The chain\n\n* [Requirement](requirement.md) - a statement of need the system must satisfy\n* [Task](task.md) - the smallest unit of executable work (produces `code`)\n* [Test](test.md) - a check that `verifies` a requirement\n\n# Common helpers\n\n* [Story](story.md) - an optional user-facing grouping above tasks\n* [Bug](bug.md) - a defect that `affects` a requirement\n\n## Want more?\n\nThis is the core profile. For the full SDLC taxonomy — Vision, PRD, the\nBusiness/Functional/NonFunctional requirement split, Initiative/Epic, planning\n(Release/Sprint/Milestone/Roadmap), Spike, Persona, and the Change/Scenario change\noverlay — run `iBuild init --full`, or copy the type files you want from the full\nprofile. Adding a type is pure data: drop its `*.md` here.\n",
  "profiles/core/overview.md": "---\ntype: Reference\ntitle: Core Type Model — the lean Requirement → Task → Code → Test chain\ndescription: The minimal iBuildOS profile and how its few types fit together.\ntags: [types, taxonomy, traceability, core]\n---\n\n# Overview (core profile)\n\nThe core profile is deliberately small: one requirement type, the work that\nimplements it, and the test that proves it — plus two optional helpers.\n\n# Inheritance\n\n```\nWorkItem (abstract: id, title, owner, status)\n├── Requirement   (status, priority)\n├── Task          (code, implements→Requirement, verified_by→Test)\n├── Test          (verifies→Requirement)\n├── Story         (optional grouping: implements→Requirement, verified_by→Test)\n└── Bug           (affects→Requirement, verified_by→Test)\n```\n\n# Traceability chain\n\n```\nRequirement ──implements──◄ Task ──code──► [source files]\n     ▲                        │\n     └────────verifies──── Test ◄──verified_by──┘\n```\n\nA Requirement is `implemented` by a Task (directly, or via a `parent` Story) and\n`verified` by a Test. The gate refuses a `done` Task whose `code` matches nothing\nor whose Test isn't `passing`, and an `accepted` Requirement that nothing\nimplements or verifies.\n\n# Growing beyond core\n\nEverything here is data. When the flat model isn't enough, `iBuild init --full`\ngives you the full taxonomy (Vision/PRD, the requirement split, Initiative/Epic,\nplanning, Spike/Persona, and the Change/Scenario overlay). You can also add any\nsingle type by dropping its `*.md` into this directory — no code change.\n",
  "profiles/core/requirement.md": "---\ntype: ArtifactType\ndefines: Requirement\nextends: WorkItem\ndescription: A statement of need the system must satisfy.\nfields:\n  id:\n    required: true\n    pattern: \"REQ-<number>\"\n    doc: Stable identifier, e.g. REQ-007.\n  status:\n    required: true\n    one_of: [proposed, accepted, implemented, deprecated]\n    doc: proposed (idea) → accepted (committed) → implemented → deprecated.\n  priority:\n    one_of: [must, should, could, wont]\n    doc: MoSCoW priority. Optional.\n---\n\n# Requirement\n\nA **Requirement** is a single need the system must satisfy — written so it can be\nimplemented and verified. Work `implements` it; a [Test](test.md) (or Scenario, in\nthe full profile) `verifies` it. Once `accepted`, the linter expects both: an\nimplementer and a verifier.\n\nThe core profile keeps requirements flat — one type. The full profile splits them\ninto Business / Functional / NonFunctional and adds the Vision → PRD chain above\nthem; switch with `iBuild init --full` or add those type files when you need them.\n",
  "profiles/core/story.md": "---\ntype: ArtifactType\ndefines: Story\nextends: WorkItem\ndescription: A user story — a small, user-facing increment of value that groups tasks.\nfields:\n  id:\n    required: true\n    pattern: \"STORY-<number>\"\n    doc: Stable identifier, e.g. STORY-022.\n  status:\n    required: true\n    one_of: [todo, in_progress, in_review, done]\n    doc: Current state.\n  as_a:\n    doc: The role — the \"As a …\" clause.\n  i_want:\n    doc: The capability — the \"I want …\" clause.\n  so_that:\n    doc: The benefit — the \"so that …\" clause.\n  acceptance_criteria:\n    type: list\n    doc: Acceptance criteria, one per item — ideally GIVEN/WHEN/THEN in RFC 2119 language (SHALL/MUST/SHOULD/MAY).\nrelationships:\n  implements:\n    target: Requirement\n    doc: The requirement(s) this story fulfils.\n  verified_by:\n    target: Test\n    doc: Acceptance tests proving the story is done.\n  parent:\n    target: WorkItem\n    max: 1\n    doc: Optional parent for grouping (e.g. a larger Story).\n---\n\n# Story\n\nA **Story** is an optional, user-facing grouping above [Task](task.md)s. It\n`implements` a [Requirement](requirement.md) and is `verified_by` a\n[Test](test.md). Tasks hang under it via their `parent` link, so a Task traces to\na requirement through its Story even when it doesn't `implements` one directly.\nSkip stories entirely if your tasks map straight to requirements.\n",
  "profiles/core/task.md": "---\ntype: ArtifactType\ndefines: Task\nextends: WorkItem\ndescription: The smallest unit of executable work — the thing you actually do.\nfields:\n  id:\n    required: true\n    pattern: \"TASK-<number>\"\n    doc: Stable identifier, e.g. TASK-014.\n  status:\n    required: true\n    one_of: [todo, in_progress, blocked, done]\n    doc: Current state. A Task is `done` only once its code exists and its test passes.\n  code:\n    type: list\n    doc: Globs of the source files this task produces or changes, e.g. internal/foo/*.go.\nrelationships:\n  implements:\n    target: Requirement\n    doc: The requirement(s) this task fulfils (directly, or inherited via parent).\n  verified_by:\n    target: Test\n    doc: The test(s) proving this task works.\n  parent:\n    target: WorkItem\n    max: 1\n    doc: Optional parent (a Story, or a larger Task) for grouping and trace-via-parent.\n---\n\n# Task\n\nA **Task** is the unit of work that produces code. It `implements` a\n[Requirement](requirement.md) — directly, or by hanging under a `parent` that\ndoes — and is `verified_by` a [Test](test.md). The gate enforces the honest\nchain: a `done` Task must have `code` globs that match real files and a `passing`\ntest, and must trace to a requirement.\n",
  "profiles/core/test.md": "---\ntype: ArtifactType\ndefines: Test\nextends: WorkItem\ndescription: A check that verifies a requirement.\nfields:\n  id:\n    required: true\n    pattern: \"TEST-<slug>\"\n    doc: Stable identifier, e.g. TEST-orders-freshness.\n  status:\n    required: true\n    one_of: [planned, automated, passing, failing]\n    doc: planned → automated → passing/failing. Only `passing` closes the chain.\nrelationships:\n  verifies:\n    target: Requirement\n    min: 1\n    doc: The requirement(s) this test proves. A test must verify at least one.\n---\n\n# Test\n\nA **Test** is the proof end of the chain. It `verifies` one or more\n[Requirement](requirement.md)s; a Task points back to it with `verified_by`. Mark\nit `passing` only when it actually passes — the gate trusts this status, so a lie\nhere is a lie in the graph.\n",
  "profiles/core/work-item.md": "---\ntype: ArtifactType\ndefines: WorkItem\nabstract: true\ndescription: Abstract base for artifacts that someone owns and that move through a lifecycle.\nfields:\n  id:\n    required: true\n    doc: Stable unique identifier. Other artifacts link to this by id, never by title.\n  title:\n    required: true\n    doc: Human-readable name.\n  owner:\n    required: true\n    doc: Person or team accountable for the artifact.\n  status:\n    required: true\n    doc: Current lifecycle state. Concrete types narrow the allowed values.\n---\n\n# WorkItem\n\nAn abstract base type. WorkItems are never created directly; concrete types such\nas [Task](task.md), [Requirement](requirement.md), and [Test](test.md) declare\n`extends: WorkItem` to inherit `id`, `title`, `owner`, and `status` without\nrepeating them.\n\n`abstract: true` tells the validator that no document may declare\n`type: WorkItem` directly — it exists only to be extended.\n",
  "profiles/full/actor.md": "---\ntype: ArtifactType\ndefines: Actor\nabstract: true\ndescription: Abstract base for an assignable identity — a User or a Team.\nfields:\n  id:\n    required: true\n    doc: Stable unique identifier. Other artifacts link to this by id.\n  name:\n    required: true\n    doc: Display name.\n---\n\n# Actor\n\nAn abstract base for the things work can be **assigned to**: a [User](user.md) or\na [Team](team.md). A WorkItem's `assignee` relationship targets `Actor`, so it is\nsatisfied polymorphically by either. This is lightweight identity for assignment\nand notification only — not a permissions, role, or approval model.\n",
  "profiles/full/adr.md": "---\ntype: ArtifactType\ndefines: ADR\nextends: WorkItem\ndescription: An Architecture Decision Record — a decision, its context, and consequences (MADR-style).\nfields:\n  id:\n    required: true\n    pattern: \"ADR-<number>\"\n    doc: Stable identifier, e.g. ADR-0001.\n  status:\n    required: true\n    one_of: [proposed, accepted, superseded, rejected, deprecated]\n    doc: Decision lifecycle.\nrelationships:\n  supersedes:\n    target: ADR\n    max: 1\n    doc: A prior decision this one replaces (decision history).\n  affects:\n    target: Requirement\n    doc: Requirement(s) or area(s) this decision constrains.\n---\n\n# ADR\n\nAn **Architecture Decision Record** captures a decision, the context that forced\nit, and its consequences. A superseded decision links to its successor via\n`supersedes`, and `affects` ties a decision to what it constrains — keeping\ndecisions inside the same traceability graph as requirements and work. The\nproject's own decisions (D-001…) are promoted to ADRs as the bundle grows.\n",
  "profiles/full/architecture.md": "---\ntype: ArtifactType\ndefines: Architecture\nextends: WorkItem\ndescription: An architecture description (C4/arc42 reference) stored in-repo and linkable.\nfields:\n  id:\n    required: true\n    pattern: \"ARCH-<slug>\"\n    doc: Stable identifier, e.g. ARCH-system-context.\n  status:\n    required: true\n    one_of: [draft, current, superseded]\n    doc: Document lifecycle.\nrelationships:\n  supersedes:\n    target: Architecture\n    max: 1\n    doc: A prior architecture description this one replaces.\n---\n\n# Architecture\n\nAn **Architecture** artifact describes structure — a C4 level, an arc42 section,\nor a text-based model that diagrams are generated from (a binary-only diagram is\nnever the source of truth). It lives in-repo and is linkable like any other\nartifact.\n",
  "profiles/full/artifact-type.md": "---\ntype: ArtifactType\ndefines: ArtifactType\ndescription: The meta-type. Defines the structure every type definition follows.\nfields:\n  defines:\n    required: true\n    doc: The name of the type this document defines.\n  extends:\n    doc: Optional parent type whose fields and relationships are inherited.\n  abstract:\n    type: bool\n    doc: If true, no document may use this type directly; it exists only to be extended.\n  description:\n    doc: One-line summary of the artifact type.\n  fields:\n    doc: Map of field name to field spec (see body).\n  relationships:\n    doc: Map of relationship name to relationship spec (see body).\n---\n\n# ArtifactType\n\nAn **ArtifactType** defines one kind of artifact in the project — a Task, a\nRequirement, an ADR, and so on. It is the *only* type the validator understands\nnatively. Every other type is just data written in this format, which is why a\nproject can define its own lifecycle without changing a line of the tool's code.\n\n`ArtifactType` is itself an `ArtifactType` (this document), so the engine\nvalidates type definitions with the same machinery it uses on everything else.\n\n## Field spec\n\nEach entry under `fields:` describes one frontmatter key that documents of this\ntype may carry.\n\n| Key        | Meaning                                                                                   |\n|------------|-------------------------------------------------------------------------------------------|\n| `required` | `true` if the field must be present. Default `false`.                                     |\n| `one_of`   | List of allowed values (an enum).                                                         |\n| `pattern`  | A string pattern. Friendly tokens: `<number>`, `<slug>`, `<date>`. Use `regex:...` raw.   |\n| `type`     | `string` (default), `number`, `date`, or `bool`.                                          |\n| `doc`      | Human description of the field.                                                           |\n\n## Relationship spec\n\nEach entry under `relationships:` declares a typed link. In an actual document\nthese appear under a `links:` block, keyed by the relationship name.\n\n| Key      | Meaning                                                          |\n|----------|------------------------------------------------------------------|\n| `target` | The artifact type every link under this name must point to.      |\n| `min`    | Minimum number of links required. Default `0`.                   |\n| `max`    | Maximum number of links allowed. Optional (unbounded if absent). |\n| `doc`    | Human description of the relationship.                           |\n\nA link satisfies `target: X` if the document it points to has type `X` **or any\ntype that extends `X`**. So a relationship whose `target` is an abstract base —\ne.g. `Requirement` or `BacklogItem` — is satisfied by any of its concrete\nsubtypes.\n\n## Escape hatch\n\nFor validation the tiny dialect can't express, a definition may include a\n`json_schema:` block. It is applied to a document's frontmatter *in addition to*\nthe rules above, so power users get full JSON Schema without forcing everyone\nelse to read it.\n\n## Example\n\nSee [Task](task.md) for a complete definition and the document it validates.\n",
  "profiles/full/backlog-item.md": "---\ntype: ArtifactType\ndefines: BacklogItem\nextends: WorkItem\nabstract: true\ndescription: Abstract base for any schedulable, prioritisable unit of work.\nfields:\n  priority:\n    one_of: [must, should, could, wont]\n    doc: MoSCoW priority.\n  estimate:\n    doc: Effort estimate (story points, t-shirt size, or hours) — the team picks the unit.\nrelationships:\n  planned_for:\n    target: Release\n    max: 1\n    doc: The release this item is slated for.\n  scheduled_in:\n    target: Sprint\n    max: 1\n    doc: The sprint this item is scheduled in. Optional under flow-based planning.\n---\n\n# BacklogItem\n\nAn abstract base — never used directly — for work that can be prioritised,\nestimated, and placed on a plan: [Initiative](initiative.md), [Epic](epic.md),\n[Story](story.md), [Task](task.md), [Bug](bug.md), and [Spike](spike.md) all\nextend it. It adds `priority` and `estimate` to the [WorkItem](work-item.md)\nbasics, plus the optional planning links `planned_for` (a [Release](release.md))\nand `scheduled_in` (a [Sprint](sprint.md)).\n\nBecause planning links live here, every kind of work item plugs into the same\nrelease and sprint plan without re-declaring how.\n",
  "profiles/full/bug.md": "---\ntype: ArtifactType\ndefines: Bug\nextends: BacklogItem\ndescription: A defect — behaviour that violates a requirement.\nfields:\n  id:\n    required: true\n    pattern: \"BUG-<number>\"\n    doc: Stable identifier, e.g. BUG-417.\n  status:\n    required: true\n    one_of: [open, in_progress, resolved, closed, wont_fix]\n    doc: Current state.\n  severity:\n    one_of: [blocker, critical, major, minor, trivial]\n    doc: Impact severity.\nrelationships:\n  parent:\n    target: Epic\n    max: 1\n    doc: Optional epic this bug is grouped under.\n  affects:\n    target: Requirement\n    doc: The requirement(s) whose behaviour is violated.\n  fixed_by:\n    target: Task\n    doc: The task(s) that fix this defect.\n  verified_by:\n    target: Test\n    doc: Regression test(s) proving the fix.\n---\n\n# Bug\n\nA **Bug** is a defect against expected behaviour. Linking `affects` to the\n[Requirement](requirement.md) it violates keeps defects inside the same\ntraceability graph as features, and `verified_by` ties the fix to a regression\n[Test](test.md).\n",
  "profiles/full/business-requirement.md": "---\ntype: ArtifactType\ndefines: BusinessRequirement\nextends: Requirement\ndescription: A need expressed in business terms.\nfields:\n  id:\n    required: true\n    pattern: \"BR-<number>\"\n    doc: Stable identifier, e.g. BR-0003.\n---\n\n# BusinessRequirement\n\nA **BusinessRequirement** states a need in business/outcome terms. It inherits\n`status`, `priority`, and `traces_to` (→ [PRD](prd.md)) from\n[Requirement](requirement.md). [FunctionalRequirement](functional-requirement.md)\nand [NonFunctionalRequirement](non-functional-requirement.md) documents\n`derives_from` a business requirement, and [Initiative](initiative.md)s\n`traces_to` them — so business intent links all the way down to delivered work.\n",
  "profiles/full/catalog-requirement.md": "---\ntype: ArtifactType\ndefines: CatalogRequirement\nextends: Requirement\ndescription: A requirement carried with its stable catalog ID (AREA-NNN), as in a master requirements specification.\nfields:\n  id:\n    required: true\n    pattern: \"regex:[A-Z]{2,3}-[0-9]{3,}\"\n    doc: Stable catalog identifier, e.g. KS-001, VL-013, NFR-007.\n  status:\n    required: true\n    one_of: [draft, accepted, implemented, deprecated]\n    doc: draft (catalogued, not yet scheduled — draws no chain findings) → accepted (committed, must be implemented + verified) → implemented → deprecated.\n  area:\n    doc: Capability-area code, e.g. KS, VL, NFR.\n---\n\n# CatalogRequirement\n\nA **CatalogRequirement** is a requirement that keeps the stable, area-coded ID it\nwas given in a master specification (e.g. `KS-001`, `NFR-007`) rather than a\nsequential `FR-<number>`. It extends [Requirement](requirement.md), so it is a\nfirst-class node in the traceability chain — but at `status: draft` it is a\ncatalogued backlog item that draws no completeness findings. As a requirement is\nscheduled into a phase it flips to `accepted` (committed), at which point the\nlinter expects it to be implemented and verified like any other requirement.\n\nThis is how IBuildOS dogfoods its own master spec: the spec is decomposed into one\nCatalogRequirement per `AREA-NNN`, and each is driven through the chain as the\nmatching capability is built.\n",
  "profiles/full/change.md": "---\ntype: ArtifactType\ndefines: Change\nextends: WorkItem\ndescription: A proposal to evolve the system — the why, the what, and the work that delivers it.\nfields:\n  id:\n    required: true\n    pattern: \"CHANGE-<slug>\"\n    doc: Stable identifier, e.g. CHANGE-orders-freshness-sla.\n  status:\n    required: true\n    one_of: [proposed, active, done, archived]\n    doc: Lifecycle — proposed (drafted), active (approved, in progress), done (delivered), archived (history).\n  scope:\n    one_of: [added, modified, removed, mixed]\n    doc: Net effect on requirements — the OpenSpec-style ADDED/MODIFIED/REMOVED delta, at a glance.\nrelationships:\n  affects:\n    target: Requirement\n    doc: Requirement(s) this change adds, modifies, or removes — the delta link.\n  delivers:\n    target: Task\n    doc: Task(s) that carry out the change — the checklist as real, traceable graph nodes.\n  supersedes:\n    target: Change\n    max: 1\n    doc: A prior change this one replaces (the rework audit chain).\n---\n\n# Change\n\nA **Change** is the unit of *evolution* — what spec-driven tools call a change\nproposal. One file captures the **why** (a `## Why` body section), the\n**what / scope** (`## What changes`), and the **technical approach** (`## Design`).\nThe work itself is `delivers` links to real [Task](task.md)s — not opaque\ncheckboxes, so each carries its own `code` + `verified_by` traceability.\n\nIt `affects` the [Requirement](requirement.md)s it touches. iBuildOS expresses\nthe delta through mechanics it already has, not a new section dialect:\n\n- **ADDED** — author a new requirement at `status: proposed`, link it under `affects`.\n- **MODIFIED** — edit the requirement in place (git is the diff/audit trail); for a\n  material rewrite, author a replacement and set the old one `status: deprecated`.\n- **REMOVED** — flip the target requirement to `status: deprecated`. Nothing is\n  deleted; deprecated requirements stop drawing chain findings.\n\nThe lifecycle is the `status` enum: `proposed` → `active` → `done` → `archived`.\nA Change draws no chain-completeness findings — it is neither a requirement nor\ntask-like — so it adds capture without adding gates. Git stays the source of\ntruth; the Change is the reviewable, linkable record of intent that a raw diff\nisn't.\n",
  "profiles/full/epic.md": "---\ntype: ArtifactType\ndefines: Epic\nextends: BacklogItem\ndescription: A large body of work broken down into stories.\nfields:\n  id:\n    required: true\n    pattern: \"EPIC-<number>\"\n    doc: Stable identifier, e.g. EPIC-031.\n  status:\n    required: true\n    one_of: [proposed, in_progress, done, cancelled]\n    doc: Current state.\nrelationships:\n  parent:\n    target: Initiative\n    max: 1\n    doc: The initiative this epic belongs to.\n  implements:\n    target: Requirement\n    doc: Requirement(s) this epic fulfils.\n  realized_by:\n    target: Story\n    doc: The stories that deliver this epic.\n---\n\n# Epic\n\nAn **Epic** is a large chunk of work under an [Initiative](initiative.md),\ndelivered through a set of [Story](story.md)s and tied to one or more\n[Requirement](requirement.md)s via `implements`. Epics are the level most teams\nplan releases around.\n",
  "profiles/full/functional-requirement.md": "---\ntype: ArtifactType\ndefines: FunctionalRequirement\nextends: Requirement\ndescription: A specific behaviour the system must provide.\nfields:\n  id:\n    required: true\n    pattern: \"FR-<number>\"\n    doc: Stable identifier, e.g. FR-0007.\nrelationships:\n  derives_from:\n    target: BusinessRequirement\n    doc: The business requirement this functional requirement refines.\n---\n\n# FunctionalRequirement\n\nA **FunctionalRequirement** describes a concrete behaviour (\"the system shall…\").\nIt refines a [BusinessRequirement](business-requirement.md) via `derives_from`,\nand is what [Epic](epic.md)s and [Story](story.md)s most often `implements`.\n",
  "profiles/full/index.md": "# Artifact Types\n\nThe SDLC profile for this project — the type definitions iBuild validates. Each\nfile is an `ArtifactType` document: human-readable docs whose frontmatter drives\nthe validator. Editing these changes what the linter enforces; nothing about the\ntypes is hardcoded in the tool. See [overview](overview.md) for how they fit\ntogether and map onto Jira and Confluence.\n\n# Meta & bases\n\n* [ArtifactType](artifact-type.md) - the meta-type; defines the dialect itself\n* [WorkItem](work-item.md) - abstract base: id, title, owner, status\n* [BacklogItem](backlog-item.md) - abstract: adds priority, estimate, release/sprint planning\n* [Requirement](requirement.md) - abstract base for the three requirement kinds\n\n# Knowledge & requirements (replaces Confluence)\n\n* [Vision](vision.md) - product strategy\n* [PRD](prd.md) - product requirements document\n* [BusinessRequirement](business-requirement.md) - a need in business terms\n* [FunctionalRequirement](functional-requirement.md) - a behaviour the system must provide\n* [NonFunctionalRequirement](non-functional-requirement.md) - a quality attribute / constraint\n* [Persona](persona.md) - a representative user\n\n# Work breakdown (replaces Jira issues)\n\n* [Initiative](initiative.md) - top-level strategic objective\n* [Epic](epic.md) - large body of work\n* [Story](story.md) - user story\n* [Task](task.md) - smallest unit of executable work\n* [Subtask](subtask.md) - fine breakdown of a task\n* [Bug](bug.md) - a defect\n* [Spike](spike.md) - time-boxed research\n* [Test](test.md) - a check that verifies a requirement\n* [Scenario](scenario.md) - a GIVEN/WHEN/THEN acceptance scenario in RFC 2119 language\n* [Change](change.md) - a proposal to evolve the system (the spec-driven change unit)\n\n# Planning (replaces Jira boards & roadmaps)\n\n* [Roadmap](roadmap.md) - sequences initiatives over time\n* [Release](release.md) - a shippable version\n* [Sprint](sprint.md) - a time-boxed iteration (optional)\n* [Milestone](milestone.md) - a dated checkpoint\n",
  "profiles/full/initiative.md": "---\ntype: ArtifactType\ndefines: Initiative\nextends: BacklogItem\ndescription: A large strategic objective spanning multiple epics.\nfields:\n  id:\n    required: true\n    pattern: \"INIT-<number>\"\n    doc: Stable identifier, e.g. INIT-007.\n  status:\n    required: true\n    one_of: [proposed, active, done, cancelled]\n    doc: Current state.\nrelationships:\n  traces_to:\n    target: BusinessRequirement\n    doc: The business requirement(s) this initiative addresses.\n  realized_by:\n    target: Epic\n    doc: The epics that deliver this initiative.\n---\n\n# Initiative\n\nAn **Initiative** is the top of the work-breakdown hierarchy — a strategic\nobjective realised by several [Epic](epic.md)s and tied to business intent via\n`traces_to` a [BusinessRequirement](business-requirement.md). Initiatives are what\na [Roadmap](roadmap.md) sequences.\n",
  "profiles/full/meeting-note.md": "---\ntype: ArtifactType\ndefines: MeetingNote\nextends: WorkItem\ndescription: A captured meeting/decision note, so coordination memory lives in the repo rather than chat.\nfields:\n  id:\n    required: true\n    pattern: \"MEET-<slug>\"\n    doc: Stable identifier, e.g. MEET-2026-06-30-planning.\n  status:\n    required: true\n    one_of: [draft, published]\n    doc: Document lifecycle.\n  date:\n    type: date\n    doc: When the meeting took place.\n---\n\n# MeetingNote\n\nA **MeetingNote** captures a meeting or decision as a linkable, version-controlled\nartifact. Optional team-coordination memory — teams that do not want it can drop\nthis type from their profile.\n",
  "profiles/full/milestone.md": "---\ntype: ArtifactType\ndefines: Milestone\nextends: WorkItem\ndescription: A date-anchored checkpoint.\nfields:\n  id:\n    required: true\n    pattern: \"MILE-<slug>\"\n    doc: Stable identifier, e.g. MILE-beta.\n  status:\n    required: true\n    one_of: [upcoming, reached, missed]\n    doc: Current state.\n  target_date:\n    required: true\n    type: date\n    doc: The date this milestone must be reached (ISO 8601).\nrelationships:\n  requires:\n    target: BacklogItem\n    doc: Work that must be complete for this milestone (any work-item subtype).\n---\n\n# Milestone\n\nA **Milestone** is a dated checkpoint — a beta, a launch, a compliance deadline.\n`requires` points at the [BacklogItem](backlog-item.md)s (epics, stories, …) that\nmust be done by `target_date`, so the linter can flag a milestone at risk when its\nrequired work is not on track.\n",
  "profiles/full/non-functional-requirement.md": "---\ntype: ArtifactType\ndefines: NonFunctionalRequirement\nextends: Requirement\ndescription: A quality attribute or constraint the system must meet.\nfields:\n  id:\n    required: true\n    pattern: \"NFR-<number>\"\n    doc: Stable identifier, e.g. NFR-0002.\n  category:\n    required: true\n    one_of: [performance, security, scalability, reliability, usability, compliance, maintainability]\n    doc: The quality attribute this requirement constrains.\nrelationships:\n  derives_from:\n    target: BusinessRequirement\n    doc: The business requirement that motivates this constraint.\n---\n\n# NonFunctionalRequirement\n\nA **NonFunctionalRequirement** (NFR) captures a quality attribute — performance,\nsecurity, reliability, and so on — rather than a feature. The required `category`\nfield keeps NFRs filterable and reportable, which is hard to do when they are\nprose scattered through Confluence pages.\n",
  "profiles/full/overview.md": "---\ntype: Reference\ntitle: SDLC Type Model — Hierarchy, Traceability, and Jira/Confluence Mapping\ndescription: How iBuildOS's artifact types fit together and replace traditional ALM tools.\ntags: [types, taxonomy, traceability]\ntimestamp: 2026-06-18T00:00:00Z\n---\n\n# Overview\n\nThis profile models the whole lifecycle as linked OKF documents. The types fall\ninto four groups: **knowledge / requirements** (the Confluence replacement),\n**work breakdown** (the Jira issue replacement), **planning** (boards, roadmaps,\nversions), and the **abstract bases** that keep them consistent.\n\n# Inheritance\n\n```\nWorkItem (abstract: id, title, owner, status)\n├── BacklogItem (abstract: + priority, estimate, planned_for→Release, scheduled_in→Sprint)\n│   ├── Initiative\n│   ├── Epic\n│   ├── Story\n│   ├── Task\n│   ├── Bug\n│   └── Spike\n├── Requirement (abstract: + status, priority, traces_to→PRD)\n│   ├── BusinessRequirement\n│   ├── FunctionalRequirement\n│   └── NonFunctionalRequirement\n├── Subtask\n├── Change · Scenario\n├── Vision · PRD · Persona\n└── Release · Sprint · Milestone · Roadmap\n```\n\nA relationship whose `target` is an abstract base accepts any subtype — so a link\nto an `FR-` document satisfies `target: Requirement`.\n\n# Work-breakdown hierarchy\n\n```\nInitiative → Epic → Story → Task → Subtask\n                     │\n                     └── Bug · Spike  (peers of Story, grouped under an Epic)\n```\n\n`parent` links climb the hierarchy (each `max: 1`); `realized_by` is the inverse\nview back down it.\n\n# Traceability chain\n\n```\nVision → PRD → BusinessRequirement → Functional / NonFunctional Requirement\n                                              │ implements\n                    Initiative → Epic → Story → Task → Subtask\n                                              │              │ implements\n                                              └ verified_by  │\n                                                  Test ◄──────┘ verifies\n```\n\nFrom idea to production: a business need (`BR`) is refined into functional and\nnon-functional requirements, which Epics and Stories `implements`, which break\ninto Tasks and Subtasks, all `verified_by` Tests. Planning is orthogonal: any\nBacklogItem is `planned_for` a Release and optionally `scheduled_in` a Sprint;\nMilestones `require` work; Roadmaps `include` Initiatives.\n\n# What replaces what\n\n| Traditional tool | iBuildOS types |\n|---|---|\n| Confluence — vision, PRDs, requirement pages, personas | Vision, PRD, Business/Functional/NonFunctional Requirement, Persona |\n| Jira — initiatives, epics, stories, tasks, sub-tasks, bugs, spikes | Initiative, Epic, Story, Task, Subtask, Bug, Spike |\n| Jira — sprints, versions, roadmaps, milestones | Sprint, Release, Roadmap, Milestone |\n| Jira test management (Xray, Zephyr) | Test |\n\nEvery one of these is a single markdown file with typed frontmatter,\nversion-controlled in git and validated by iBuild — so the relationships above are\ncheckable, not aspirational.\n",
  "profiles/full/persona.md": "---\ntype: ArtifactType\ndefines: Persona\nextends: WorkItem\ndescription: A representative user the product serves.\nfields:\n  id:\n    required: true\n    pattern: \"PERSONA-<slug>\"\n    doc: Stable identifier, e.g. PERSONA-data-engineer.\n  status:\n    required: true\n    one_of: [draft, approved]\n    doc: Document lifecycle.\n  role:\n    doc: Short role label, e.g. \"On-call data engineer\".\n---\n\n# Persona\n\nA **Persona** describes a representative user — goals, context, pain points.\n[Story](story.md) documents reference a persona via `persona`, which keeps the\n\"As a …\" clause of every user story pointing at a real, shared definition instead\nof an ad-hoc phrase.\n",
  "profiles/full/prd.md": "---\ntype: ArtifactType\ndefines: PRD\nextends: WorkItem\ndescription: Product Requirements Document — scopes a product area into requirements.\nfields:\n  id:\n    required: true\n    pattern: \"PRD-<number>\"\n    doc: Stable identifier, e.g. PRD-014.\n  status:\n    required: true\n    one_of: [draft, in_review, approved, superseded]\n    doc: Document lifecycle.\nrelationships:\n  realizes:\n    target: Vision\n    max: 1\n    doc: The vision this PRD advances.\n---\n\n# PRD\n\nA **Product Requirements Document** frames a slice of product intent. Individual\n[Requirement](requirement.md) documents `traces_to` a PRD, and the PRD itself\n`realizes` a [Vision](vision.md). PRDs replace the requirement and spec pages\nteams keep in Confluence — but here each requirement is its own linkable,\nvalidatable artifact rather than a heading buried in a wiki page.\n",
  "profiles/full/release.md": "---\ntype: ArtifactType\ndefines: Release\nextends: WorkItem\ndescription: A shippable version that backlog items are planned into.\nfields:\n  id:\n    required: true\n    pattern: \"REL-<slug>\"\n    doc: Stable identifier, e.g. REL-2026-q3.\n  version:\n    pattern: 'regex:^v?\\d+\\.\\d+(\\.\\d+)?$'\n    doc: Semantic version, e.g. v1.4.0.\n  status:\n    required: true\n    one_of: [planned, in_progress, released]\n    doc: Current state.\n  target_date:\n    type: date\n    doc: Planned release date (ISO 8601).\n---\n\n# Release\n\nA **Release** (or Version) is a shippable cut. Work items declare `planned_for` a\nrelease on [BacklogItem](backlog-item.md), so a release's contents are derived\nfrom the graph rather than maintained as a separate list. Release notes can be\ngenerated by walking everything `planned_for` it.\n",
  "profiles/full/requirement.md": "---\ntype: ArtifactType\ndefines: Requirement\nextends: WorkItem\nabstract: true\ndescription: Abstract base for a statement of need the system must satisfy.\nfields:\n  id:\n    required: true\n    doc: Stable identifier. Concrete subtypes set their own prefix (BR-, FR-, NFR-).\n  status:\n    required: true\n    one_of: [proposed, accepted, implemented, deprecated]\n    doc: Lifecycle of the requirement.\n  priority:\n    one_of: [must, should, could, wont]\n    doc: MoSCoW priority.\nrelationships:\n  traces_to:\n    target: PRD\n    max: 1\n    doc: The product requirements document this requirement derives from.\n---\n\n# Requirement\n\nAn abstract base (never used directly) for the three concrete requirement kinds:\n[BusinessRequirement](business-requirement.md),\n[FunctionalRequirement](functional-requirement.md), and\n[NonFunctionalRequirement](non-functional-requirement.md). It is the hub of the\ntraceability graph — Epics and Stories `implements` requirements, and Tests\n`verifies` them.\n\nBecause relationships that target `Requirement` accept any of its subtypes (see\n[ArtifactType](artifact-type.md)), a Story implementing an `FR-` document\nsatisfies a `target: Requirement` link.\n\nA requirement at status `accepted` with nothing implementing or verifying it is\nan orphan the validator flags.\n",
  "profiles/full/requirements-specification.md": "---\ntype: ArtifactType\ndefines: RequirementsSpecification\ndescription: A master requirements specification document — the scope-complete catalog, later decomposed into individual Requirements.\nfields:\n  title:\n    required: true\n    doc: Document title.\n  description:\n    doc: One-paragraph summary.\n  status:\n    one_of: [draft, in_review, approved, superseded]\n    doc: Document lifecycle.\n  version:\n    doc: Semantic version of the specification.\n  date:\n    type: date\n    doc: Last-edited date.\n  owner:\n    doc: Accountable author.\n  tags:\n    type: list\n    doc: Free-form tags.\n---\n\n# RequirementsSpecification\n\nA **RequirementsSpecification** is a whole-catalog requirements document. It is a\nknowledge artifact (not a work item): it carries no `id` and draws no chain\nfindings. The authoritative, per-requirement artifacts are produced by\n*decomposing* it into individual [Requirement](requirement.md) documents; this\ntype lets the master document itself live in the repo as a validatable artifact\nin the meantime.\n",
  "profiles/full/retro-action.md": "---\ntype: ArtifactType\ndefines: RetroAction\nextends: WorkItem\ndescription: An action item from a retrospective, tracked to completion.\nfields:\n  id:\n    required: true\n    pattern: \"RETRO-<number>\"\n    doc: Stable identifier, e.g. RETRO-0007.\n  status:\n    required: true\n    one_of: [open, in_progress, done]\n    doc: Action lifecycle.\n---\n\n# RetroAction\n\nA **RetroAction** is a follow-up committed to in a retrospective. It inherits\n`assignee` from [WorkItem](work-item.md) so the action lands on a named\n[Actor](actor.md), and is tracked to `done` rather than lost in chat.\n",
  "profiles/full/roadmap.md": "---\ntype: ArtifactType\ndefines: Roadmap\nextends: WorkItem\ndescription: A time-ordered plan of initiatives.\nfields:\n  id:\n    required: true\n    pattern: \"ROAD-<slug>\"\n    doc: Stable identifier, e.g. ROAD-2026.\n  status:\n    required: true\n    one_of: [draft, active, archived]\n    doc: Current state.\n  horizon:\n    doc: The planning horizon, e.g. \"2026-H2\".\nrelationships:\n  includes:\n    target: Initiative\n    doc: The initiatives sequenced on this roadmap.\n---\n\n# Roadmap\n\nA **Roadmap** sequences [Initiative](initiative.md)s over a planning `horizon`.\nIt is the planning view that, in Jira/Confluence, lives in a separate roadmap tool\nor a slide deck — here it is a versioned artifact that links to the real\ninitiatives, so it cannot drift out of sync with the work.\n",
  "profiles/full/runbook.md": "---\ntype: ArtifactType\ndefines: Runbook\nextends: WorkItem\ndescription: An operational runbook — release and on-call knowledge.\nfields:\n  id:\n    required: true\n    pattern: \"RUN-<slug>\"\n    doc: Stable identifier, e.g. RUN-deploy-rollback.\n  status:\n    required: true\n    one_of: [draft, active, deprecated]\n    doc: Document lifecycle.\n---\n\n# Runbook\n\nA **Runbook** captures operational knowledge — how to deploy, roll back, or\nrespond on-call — as a version-controlled artifact next to the code it operates.\n",
  "profiles/full/scenario.md": "---\ntype: ArtifactType\ndefines: Scenario\nextends: WorkItem\ndescription: A single GIVEN/WHEN/THEN acceptance scenario in RFC 2119 language — an executable contract for a requirement.\nfields:\n  id:\n    required: true\n    pattern: \"SCEN-<slug>\"\n    doc: Stable identifier, e.g. SCEN-orders-lag-alert.\n  status:\n    required: true\n    one_of: [draft, accepted, verified]\n    doc: draft (written), accepted (agreed), verified (a passing test proves it).\n  given:\n    doc: Precondition — the \"GIVEN\" clause.\n  when:\n    doc: Trigger — the \"WHEN\" clause.\n  then:\n    required: true\n    doc: Expected outcome with an RFC 2119 keyword — the system SHALL / MUST / SHOULD / MAY …\nrelationships:\n  verifies:\n    target: Requirement\n    min: 1\n    doc: The requirement this scenario makes concrete (the same relationship a Test uses).\n  verified_by:\n    target: Test\n    doc: The automated test that proves this scenario passes.\n---\n\n# Scenario\n\nA **Scenario** is one GIVEN/WHEN/THEN acceptance condition stated in RFC 2119\nlanguage — the `#### Scenario:` block of a spec, promoted to a first-class,\nlinkable graph node. It sits between a [Requirement](requirement.md) (which it\n`verifies` — makes concrete) and a [Test](test.md) (`verified_by` — which proves\nit).\n\nBecause the completeness check counts *any* `verifies` edge toward a requirement\nbeing verified, a Scenario makes requirements verifiable through human-readable\nacceptance criteria — with no engine change. Use a Scenario when a criterion\ndeserves to be traced to a test; for a quick inline definition-of-done, the\n`acceptance_criteria` list on [Story](story.md) is enough.\n\nState the `then` with an RFC 2119 keyword so the obligation is unambiguous:\n\n> GIVEN an order older than the freshness SLA\n> WHEN the staleness check runs\n> THEN the system MUST raise a freshness alert within 60 seconds\n",
  "profiles/full/spike.md": "---\ntype: ArtifactType\ndefines: Spike\nextends: BacklogItem\ndescription: A time-boxed investigation to reduce uncertainty.\nfields:\n  id:\n    required: true\n    pattern: \"SPIKE-<number>\"\n    doc: Stable identifier, e.g. SPIKE-012.\n  status:\n    required: true\n    one_of: [todo, in_progress, done]\n    doc: Current state.\n  timebox:\n    doc: The agreed time budget, e.g. \"2 days\".\nrelationships:\n  parent:\n    target: Epic\n    max: 1\n    doc: Optional epic this spike supports.\n  informs:\n    target: Requirement\n    doc: Requirement(s) or decisions this research will inform.\n---\n\n# Spike\n\nA **Spike** is a time-boxed research task used to answer a question before\ncommitting to delivery. The `timebox` field keeps it bounded, and `informs`\nrecords which [Requirement](requirement.md)s or decisions the findings feed.\n",
  "profiles/full/sprint.md": "---\ntype: ArtifactType\ndefines: Sprint\nextends: WorkItem\ndescription: A time-boxed iteration. Optional under flow-based planning.\nfields:\n  id:\n    required: true\n    pattern: \"SPRINT-<number>\"\n    doc: Stable identifier, e.g. SPRINT-48.\n  status:\n    required: true\n    one_of: [planned, active, closed]\n    doc: Current state.\n  start_date:\n    type: date\n    doc: First day of the sprint (ISO 8601).\n  end_date:\n    type: date\n    doc: Last day of the sprint (ISO 8601).\n  goal:\n    doc: The sprint goal.\n---\n\n# Sprint\n\nA **Sprint** (iteration) is a time-box that [BacklogItem](backlog-item.md)s are\n`scheduled_in`. It is optional: Kanban/flow teams can ignore this type entirely\nand plan with [Release](release.md)s and [Milestone](milestone.md)s instead — the\ngeneric-agile profile keeps it available without forcing it.\n",
  "profiles/full/standup-log.md": "---\ntype: ArtifactType\ndefines: StandupLog\nextends: WorkItem\ndescription: A standup log entry, captured as version-controlled team memory.\nfields:\n  id:\n    required: true\n    pattern: \"STANDUP-<slug>\"\n    doc: Stable identifier, e.g. STANDUP-2026-06-30.\n  status:\n    required: true\n    one_of: [logged]\n    doc: Lifecycle (logged once recorded).\n  date:\n    type: date\n    doc: The standup date.\n---\n\n# StandupLog\n\nA **StandupLog** records a standup as a linkable artifact, so what the team said\nit would do is part of the repo's memory rather than ephemeral chat.\n",
  "profiles/full/story.md": "---\ntype: ArtifactType\ndefines: Story\nextends: BacklogItem\ndescription: A user story — a small, user-facing increment of value.\nfields:\n  id:\n    required: true\n    pattern: \"STORY-<number>\"\n    doc: Stable identifier, e.g. STORY-022.\n  status:\n    required: true\n    one_of: [todo, in_progress, in_review, done]\n    doc: Current state.\n  as_a:\n    doc: The role/persona — the \"As a …\" clause.\n  i_want:\n    doc: The capability — the \"I want …\" clause.\n  so_that:\n    doc: The benefit — the \"so that …\" clause.\n  acceptance_criteria:\n    type: list\n    doc: Acceptance criteria, one per item — ideally GIVEN/WHEN/THEN in RFC 2119 language (SHALL/MUST/SHOULD/MAY). For a criterion that deserves a test link, author a Scenario instead.\nrelationships:\n  parent:\n    target: Epic\n    max: 1\n    doc: The epic this story belongs to.\n  persona:\n    target: Persona\n    max: 1\n    doc: The persona this story serves.\n  implements:\n    target: Requirement\n    doc: The requirement(s) this story fulfils.\n  verified_by:\n    target: Test\n    doc: Acceptance tests proving the story is done.\n---\n\n# Story\n\nA **Story** (user story) is the primary unit of user-facing value. The `as_a` /\n`i_want` / `so_that` fields capture the classic template, `persona` points at the\n[Persona](persona.md) it serves, and `acceptance_criteria` (plus a body section)\ndefine \"done\". Stories roll up to an [Epic](epic.md), break down into\n[Task](task.md)s, `implements` [Requirement](requirement.md)s, and are\n`verified_by` [Test](test.md)s.\n",
  "profiles/full/subtask.md": "---\ntype: ArtifactType\ndefines: Subtask\nextends: WorkItem\ndescription: A fine-grained breakdown of a single task.\nfields:\n  id:\n    required: true\n    pattern: \"SUB-<number>\"\n    doc: Stable identifier, e.g. SUB-104.\n  status:\n    required: true\n    one_of: [todo, in_progress, done]\n    doc: Current state.\nrelationships:\n  parent:\n    target: Task\n    min: 1\n    max: 1\n    doc: The task this subtask breaks down. Required — subtasks never stand alone.\n---\n\n# Subtask\n\nA **Subtask** is the finest level of breakdown, always belonging to exactly one\n[Task](task.md) (`parent` is required, `min: 1`, `max: 1`). It extends\n[WorkItem](work-item.md) rather than [BacklogItem](backlog-item.md): subtasks\ninherit planning context from their parent task instead of being planned on their\nown.\n",
  "profiles/full/task.md": "---\ntype: ArtifactType\ndefines: Task\nextends: BacklogItem\ndescription: The smallest unit of executable work.\nfields:\n  id:\n    required: true\n    pattern: \"TASK-<number>\"\n    doc: Stable unique identifier, e.g. TASK-014.\n  status:\n    required: true\n    one_of: [todo, in_progress, blocked, done]\n    doc: Current lifecycle state.\n  code:\n    type: list\n    doc: Repo-relative path globs to the source this task produces. At least one must match a file on disk; a `done` task must declare code.\nrelationships:\n  parent:\n    target: Story\n    max: 1\n    doc: The user story this task helps deliver.\n  implements:\n    target: Requirement\n    doc: Requirement(s) this task fulfils directly (optional when the reason comes from its parent Story).\n  verified_by:\n    target: Test\n    doc: Tests that prove this task is complete.\n---\n\n# Task\n\nA **Task** is the smallest unit of executable work. It extends\n[BacklogItem](backlog-item.md) (so it can be prioritised, estimated, and planned)\nand usually rolls up to a [Story](story.md) via `parent`.\n\nA task must trace to a [Requirement](requirement.md) — either directly through\n`implements`, or transitively through its parent Story — and should be\n`verified_by` at least one [Test](test.md) before it is marked `done`. The Phase 1\nlinter enforces this `Requirement → Task → Test` chain.\n\n## Example\n\nA conformant task document (e.g. `work/task-014.md`):\n\n```markdown\n---\ntype: Task\nid: TASK-014\ntitle: Add freshness SLA alert to orders pipeline\nstatus: in_progress\nowner: srini\npriority: should\nlinks:\n  parent:      [/work/story-022.md]\n  implements:  [/requirements/fr-0007.md]\n  verified_by: [/tests/test-orders-freshness.md]\n---\n\nWire a freshness check into the orders pipeline that raises an alert when the\ndata lags its SLA by more than 30 minutes.\n```\n",
  "profiles/full/team.md": "---\ntype: ArtifactType\ndefines: Team\nextends: Actor\ndescription: A group of Users that work can be assigned to.\nfields:\n  id:\n    required: true\n    pattern: \"TEAM-<slug>\"\n    doc: Stable identifier, e.g. TEAM-platform.\nrelationships:\n  members:\n    target: User\n    doc: The Users on this team.\n---\n\n# Team\n\nA **Team** groups [User](user.md)s. Work can be assigned to a Team (via a work\nitem's `assignee`) the same way it is assigned to an individual, because both\nextend [Actor](actor.md).\n",
  "profiles/full/test-result.md": "---\ntype: ArtifactType\ndefines: TestResult\ndescription: A captured test-run outcome, stored as a versioned OKF artifact (decision D-009).\nfields:\n  id:\n    required: true\n    pattern: \"RESULT-<slug>\"\n    doc: Stable identifier, e.g. RESULT-ci-2026-06-30.\n  status:\n    required: true\n    one_of: [passed, failed, skipped, errored]\n    doc: Outcome of the run.\n  ran_at:\n    type: date\n    doc: Date the run was captured.\n  runner:\n    doc: The command/runner that produced this result.\nrelationships:\n  result_of:\n    target: Test\n    max: 1\n    doc: The Test this result records an outcome for.\n---\n\n# TestResult\n\nA **TestResult** is a test-run outcome captured as a version-controlled artifact\nrather than a transient CI log (decision D-009). `iBuild test` orchestrates the\nproject's existing runner and records results here; automated CI results and\nmanual outcomes both live in the same shape. It is a result record, not a work\nitem, so it draws no chain findings.\n",
  "profiles/full/test.md": "---\ntype: ArtifactType\ndefines: Test\nextends: WorkItem\ndescription: A check that verifies a requirement is satisfied.\nfields:\n  id:\n    required: true\n    pattern: \"TEST-<slug>\"\n    doc: Stable unique identifier, e.g. TEST-orders-freshness.\n  status:\n    required: true\n    one_of: [planned, automated, passing, failing]\n    doc: Current state of the test.\nrelationships:\n  verifies:\n    target: Requirement\n    min: 1\n    doc: The requirement(s) this test proves are satisfied.\n---\n\n# Test\n\nA **Test** proves that a [Requirement](requirement.md) is satisfied. It must\n`verifies` at least one requirement.\n\nTwo situations are gaps the validator reports: a requirement with no test\nverifying it, and a Task marked `done` whose `verified_by` tests are not yet\n`passing`.\n",
  "profiles/full/user.md": "---\ntype: ArtifactType\ndefines: User\nextends: Actor\ndescription: A contributor, mapped to a git user identity. Lightweight identity for assignment and notification — not auth.\nfields:\n  id:\n    required: true\n    pattern: \"USER-<slug>\"\n    doc: Stable identifier, e.g. USER-srini.\n  git_email:\n    doc: The git identity (email) this user maps to, so artifacts and changes attribute via git history.\n  handle:\n    doc: Optional chat/VCS handle.\n---\n\n# User\n\nA **User** is a contributor identity that maps to a git user (name + optional\nemail/handle). An artifact's `owner` field and a work item's `assignee` link\nresolve to a User, so authorship and assignment attribute to real people via git\nhistory rather than depending on `CODEOWNERS`. Roles, permissions, and approval\nauthority are out of scope.\n",
  "profiles/full/vision.md": "---\ntype: ArtifactType\ndefines: Vision\nextends: WorkItem\ndescription: The product vision and strategy — the top of the knowledge tree.\nfields:\n  id:\n    required: true\n    pattern: \"VIS-<slug>\"\n    doc: Stable identifier, e.g. VIS-platform.\n  status:\n    required: true\n    one_of: [draft, approved, archived]\n    doc: Document lifecycle.\n---\n\n# Vision\n\nA **Vision** captures product strategy and direction — the \"why\" everything else\ntraces back to. [PRD](prd.md) documents `realizes` a Vision, and\n[BusinessRequirement](business-requirement.md)s ultimately ladder up to it. This\nis part of the knowledge layer that replaces strategy pages in Confluence.\n",
  "profiles/full/work-item.md": "---\ntype: ArtifactType\ndefines: WorkItem\nabstract: true\ndescription: Abstract base for artifacts that someone owns and that move through a lifecycle.\nfields:\n  id:\n    required: true\n    doc: Stable unique identifier. Other artifacts link to this by id, never by title.\n  title:\n    required: true\n    doc: Human-readable name.\n  owner:\n    required: true\n    doc: Person or team accountable for the artifact (resolves to a User; see WP-008).\n  status:\n    required: true\n    doc: Current lifecycle state. Concrete types narrow the allowed values.\nrelationships:\n  assignee:\n    target: Actor\n    max: 1\n    doc: The User or Team currently doing the work (optional; notified on assignment).\n---\n\n# WorkItem\n\nAn abstract base type. WorkItems are never created directly; concrete types such\nas [Task](task.md), [Requirement](requirement.md), and [Test](test.md) declare\n`extends: WorkItem` to inherit `id`, `title`, `owner`, and `status` without\nrepeating them.\n\n`abstract: true` tells the validator that no document may declare\n`type: WorkItem` directly — it exists only to be extended.\n",
};
